import { log } from "cc";
import { newBottombarManager, BaseState, commonGameManager, SlotBottomBarState, stateManager, soundManager, eventManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define, { RespinType } from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import protocol from "@igs-arcade-division-rd2/uk_746_far_west_proto/ar2fwProto.js";
import { COWBOY_EVENT } from "../CowboyController";

/**@ch 小偷respin的等待時間 */
const RESPIN_WAIT_TIME_THIEF = 2;
/**@ch Super5 respin的延遲時間 */
const RESPIN_DELAY_TIME_SUPER5 = 1;
/**@ch Super5 respin的等待時間 */
const RESPIN_WAIT_TIME_SUPER5 = 4;
/**@ch Super5 respin失敗的等待時間 */
const RESPIN_WAIT_TIME_SUPER5_FAIL = 0.8;

export class RespinState extends BaseState {
    private m_gameView: GameView = null;

    /**@ch 是否正在spin中，決定是否要做spin update */
    private m_isSpinning = false;
    /**@ch 目標respin的列，小偷最終的respin列，牛仔開1槍會加一筆資料到m_currentRespinCols */
    private m_targetRespinCols: number[] = null;
    /**@ch 目前respin的列 */
    private m_currentRespinCols: number[] = null;

    /**@ch 是否是Super5 respin */
    private m_isSuper5Respin: boolean = false;

    constructor(gameView: GameView) {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter() {

        log("OnEnter State : RESPIN");

        // 先不做spin update，等轉輪要動再設成true
        this.m_isSpinning = false;

        // 重置效果盤面，清除所有效果
        this.m_gameView.EffectPlate.ResetAll();
        this.m_gameView.ClearAll();

        // 取得盤面資訊
        const plateInfo = this.m_gameView.PlateInfo;

        // 判斷respin模式
        this.m_isSuper5Respin = false;
        const respinMode = plateInfo.RespinTriggerMode;
        if (respinMode === protocol.ar2fwProto.AwardModeFlag.AWARD_MODE_LINE) {
            // 小偷respin

            // 整理出小偷symbol的位置
            this.m_targetRespinCols = plateInfo.RespinCols;
            const thiefSymbols = [];
            for (let i = 0; i < plateInfo.RespinCols.length; i++) {
                const colIndex = plateInfo.RespinCols[i];
                const col = plateInfo.PlateSymbol[colIndex];
                for (let j = 0; j < col.Col.length; j++) {
                    if (col.Col[j].Symbol === Game_Define.Symbol.Thief) {
                        thiefSymbols.push({ col: colIndex, row: j });
                        break;
                    }
                }
            }

            // 叫牛仔
            await this.CallCowboyForThiefRespin(thiefSymbols);

            await Define.Wait(this.m_gameView, RESPIN_WAIT_TIME_THIEF);
        }
        else if (respinMode === protocol.ar2fwProto.AwardModeFlag.AWARD_MODE_SUPER5) {
            // Super5 respin

            this.m_isSuper5Respin = true;

            // 非respin列上的symbol表演bingo動態
            this.m_currentRespinCols = plateInfo.RespinCols;
            const respinCol: number = plateInfo.RespinCols[0];  // super5 respin只會有一列
            const lineIDs: number[] = plateInfo.WaitingLineIds;
            this.m_gameView.EffectPlate.ShowSymbolEffect_Super5(lineIDs, respinCol, RESPIN_DELAY_TIME_SUPER5);

            await Define.Wait(this.m_gameView, RESPIN_DELAY_TIME_SUPER5);

            // 顯示Super5聽牌動畫
            this.m_gameView.EffectPlate.ShowNearWinFrame_Super5(respinCol);

            // 開始spin
            this.StartSpin(RespinType.Super5);

            await Define.Wait(this.m_gameView, RESPIN_WAIT_TIME_SUPER5);
        }


        // 更新盤面資訊，準備停輪
        this.m_gameView.SlotReels?.SetPlateInfo(this.m_gameView.PlateInfo);
        this.m_gameView.SlotReels?.ClickStopBtn();
    }

    public OnProcess(dt: number) {

        if (!this.m_isSpinning) {
            return;
        }

        // 做spin update
        this.m_gameView.SlotReels.Spin(dt, this.m_currentRespinCols);
        if (!this.m_gameView.SlotReels.IsStop) {
            return;
        }

        // 停輪了
        this.ProcessAfterStop();
    }

    public OnLeave() {
        this.m_gameView.EffectPlate.ResetAll();
        this.m_gameView.SlotReels.ShowPlate();
    }

    /**@ch 開始spin */
    private StartSpin(respinType: RespinType) {
        this.m_gameView.CurPlateIndex = this.m_gameView.CurPlateIndex + 1;
        this.m_gameView.SlotReels.StartSpin(respinType);
        this.m_isSpinning = true;
    }

    /**@ch 叫牛仔出來表演小偷respin */
    private async CallCowboyForThiefRespin(thiefSymbols: { col: number, row: number }[]): Promise<void> {
        this.m_currentRespinCols = [];
        return new Promise<void>((resolve) => {
            let callbackCount = 0;
            const callback = () => {
                const col = this.m_targetRespinCols[this.m_currentRespinCols.length];
                this.m_currentRespinCols.push(col);
                if (this.m_currentRespinCols.length === 1) {
                    this.StartSpin(RespinType.Thief);
                } else {
                    this.m_gameView.SlotReels.SetColDelayTimeByCurTime(col);
                }

                callbackCount++;
                if (this.m_currentRespinCols.length === this.m_targetRespinCols.length || callbackCount >= thiefSymbols.length) {
                    resolve();
                }
            }

            const callbackArray: (() => void)[] = new Array(thiefSymbols.length).fill(callback);
            eventManager.Dispatch(COWBOY_EVENT.ENTER, thiefSymbols, callbackArray);
        });
    }

    /**@ch 處理spin結束後的流程 */
    private async ProcessAfterStop() {
        if (this.m_isSuper5Respin) {
            // super 5

            if (this.m_gameView.SlotReels.IsSuperFail) {
                // super 5失敗時聽牌框要故意多停留一下
                await Define.Wait(this.m_gameView, RESPIN_WAIT_TIME_SUPER5_FAIL);
            }

            // 停止Super5聽牌動畫
            this.m_gameView.EffectPlate.StopNearWinFrame_Super5();
        }

        this.m_gameView.CanPlateStop = true;
        this.m_gameView.CanSpaceStop = true;
        // this.m_gameView.IsSpined = false;
        if (!newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        }

        stateManager.NextState(Game_Define.GameState.EFFECT_START);
    }
}

import { Enum, Vec3, color, v3 } from "cc";
import { newBottombarManager } from "db://astarte-framework/Managers";




enum GAMEVIEW_STATE {
    WAIT_READY,
    PLATE_SHOW,
    FEATURE_SHOW,
    UNSHOW_PREPARE,
    AWARD,
    ROUND_SHOW_END,
    ROUND_END,

    EFFECT_START,
    // CHECK_JP,
    SCATTER_SHOW,
    ENTER_FREE,
    FULL_REWARD,
    LEAVE_FREE,
    ADD_FREE,
    //TODO
    ENTER_BONUS,
    BONUS_GAME,
    LEAVE_BONUS,

    RESPIN,
}

/**@ch 遊戲事件 */
enum GameEvent {
    /**押注值變化*/
    BetValueChange = "BetValueChange",
    /**symbol中獎表演，參數為AwardLineData的陣列*/
    SymbolWin = "SymbolWin",
    /**賠率初始化，參數為GameInfoData.OddsGameInfoData.OddsSuper5和初始bet值*/
    OddsInit = "OddsInit",
    /**假轉輪重置，參數為plateIdx, cols, symbolIdx, mysterySymbols*/
    FakeReelReset = "FakeReelReset",
    /**假轉輪獲得下一個symbol，參數為plateIdx, col, callback(symbol: number) => void*/
    FakeReelGetNextSymbol = "FakeReelGetNextSymbol",
}

/**@ch 牛仔動畫名稱常數 */
export const COWBOY_ANIM = {
    IDLE: 'Idle',
    RUN: 'Run',
    SHUT_BOTTOM: 'Shut_Bottom',
    SHUT_BOTTOM_TURN: 'Shut_Bottom_Turn',
    SHUT_BOTTOM_TURN_MISS: 'Shut_Bottom_Turn_Miss',
    SHUT_BOTTOM_TURN_SUCCESS: 'Shut_Bottom_Turn_Sucess',
    SHUT_BOTTOM_TURN_TO_IDLE: 'Shut_Bottom_TurntoIdle',
    SHUT_MIDDLE: 'Shut_Middle',
    SHUT_MIDDLE_TURN: 'Shut_Middle_Turn',
    SHUT_MIDDLE_TURN_MISS: 'Shut_Middle_Turn_Miss',
    SHUT_MIDDLE_TURN_SUCCESS: 'Shut_Middle_Turn_Sucess',
    SHUT_MIDDLE_TURN_TO_IDLE: 'Shut_Middle_TurntoIdle',
    SHUT_MIDDLE_TO_TOP: 'Shut_MiddletoTop',
    SHUT_TOP: 'Shut_Top',
    SHUT_TOP_TURN: 'Shut_Top_Turn',
    SHUT_TOP_TURN_MISS: 'Shut_Top_Turn_Miss',
    SHUT_TOP_TURN_SUCCESS: 'Shut_Top_Turn_Sucess',
    SHUT_TOP_TURN_TO_IDLE: 'Shut_Top_TurntoIdle',
    SHUT_TOP_TO_MIDDLE: 'Shut_ToptoMiddle',
    SUCCESS: 'Shut_Sucess',
    MISS: 'Shut_Miss',
    MISS_TURN_TO_IDLE: 'Shut_Miss_to_Idle',
};

//需與SlotReels的symbol擺放順序相同
enum Symbol {
    /**Wild(炸彈)*/
    Wild,
    /**牛仔*/
    Cowboy,
    /**女士*/
    Lady,
    /**老大*/
    Boss,
    /**商人*/
    Merchant,
    /**警徽*/
    Badge,
    /**野馬*/
    Horse,
    /**手槍*/
    Gun,
    /**牛骨*/
    Bone,
    /**仙人掌*/
    Cactus,
    /**Scatter(懸賞圖)*/
    Scatter,
    /**小偷*/
    Thief,
    /**神秘符號(server專用，client沒有對應的symbol)*/
    Mystery,
    /**Empty*/
    MAX,
}

export enum SymbolEffectPrefabs {
    /**Wild(炸彈)*/
    Wild,
    /**牛仔*/
    Cowboy,
    /**女士*/
    Lady,
    /**老大*/
    Boss,
    /**商人*/
    Merchant,
    /**警徽*/
    Badge,
    /**野馬*/
    Horse,
    /**手槍*/
    Gun,
    /**牛骨*/
    Bone,
    /**仙人掌*/
    Cactus,
    /**Scatter(懸賞圖)*/
    Scatter,
    /**小偷*/
    Thief,
    /**壓黑*/
    Dark,
    /**Scatter(懸賞圖)聽牌*/
    ScatterNearWin,
    /**中獎框*/
    WinFrame,
    /**小偷定位*/
    ThiefStop,
}

export enum WinType {
    NoWin = -2,
    /**0 < 倍率 < PlateEftOdds[1] */
    NormalWin = -1,
    /**PlateEftOdds[1] <= 倍率 < PlateEftOdds[2] */
    BigWin = 1,
    /**PlateEftOdds[2] <= 倍率 < PlateEftOdds[3] */
    MegaWin = 2,
    /**PlateEftOdds[3] <= 倍率 */
    SuperWin = 3,
}

export enum RespinType {
    /**一般spin*/
    None,
    /**小偷respin*/
    Thief,
    /**Super5 respin*/
    Super5,
}

export enum RT_EVENT {
    INIT = "INIT",
    CLOSE_RT_CAMERA = "CLOSE_RT_CAMERA",
    AWARD_IN_RT = "AWARD_IN_RT",
    AWARD_OUT_RT = "AWARD_OUT_RT",
}

export default class Game_Define {
    static Ver: string = "Ver";
    static BgAudioId: number = -1;
    static SPICY_LEVEL = 2;
    static Symbol = Enum(Symbol);
    static GameState = Enum(GAMEVIEW_STATE);
    static GameEvent = Enum(GameEvent);

    /**@ch For盤面壓黑 */
    static Color = {
        Light: color(255, 255, 255),
        Dark: color(101.25, 94.5, 73.5),
    };

    /**@ch 取得當前BET，會受extraBet影響 */
    static GetNowBetValue() {
        return newBottombarManager.GetNowBetValue();
    }

    /************************** 多語系 **************************/
    static BUY_BONUS_TXT = [
        "Txt_Buy_Feature_Bet",
        "Txt_Buy_Feature_Title",
        "BuyBonus_IconName",
    ];

    static COL = 5;
    static ROW = 3;
    static SeparateLineWidth = 4; // pixels

    static SymbolHeight = 0;    // 在SlotReels中初始化
    static SymbolWidth = 0;    // 在SlotReels中初始化

    /**@ch 表演輪(上) */
    static UP_PLATE_INDEX = 2;
    /**@ch 表演輪(中)，實際轉輪 */
    static MIDDLE_PLATE_INDEX = 1;
    /**@ch 表演輪(下) */
    static LOW_PLATE_INDEX = 0;

    static NODE_PREFIX_NAME = [
        "low",
        "",
        "up"
    ];

    static THOUSAND = 1000;
    static MILLION = 1000000;

    /**@ch Effect表演分層數，視各遊戲需求*/
    static LAYERS = {
        /**@ch 壓黑*/
        SYMBOL_DARK: 0,
        /**@ch symbol動態*/
        SYMBOL: 1,
        /**@ch 中獎框*/
        WIN_FRAME: 2,
        MAX: 3,
    };


    /**@ch 遊戲中須創造之表演大分類，(以此三幣瑞龍為例，symbol算一種、飛行特效算一種、盤面共用中獎特效算一種，共三種) */
    static EFFECT_TYPES = 2;
    static EFFECT_TYPE = {
        SYMBOL: 0,
        NEAR_WIN_FRAME: 1,
    };

    static NEAR_WIN_FRAME_TYPE = {
        /**@ch scatter聽牌框*/
        SCATTER: 0,
        /**@ch Super5聽牌框*/
        SUPER_5: 1,
    };

    static SpeedUp = 1;

    static PlateEftOdds = [1, 10, 20, 50];

    static SERVER_RET_TYPE = {
        SERVER_SUCCESS: 0, //正常				
        SERVER_ERROR_SEATE: 799, // 錯誤狀態				
        SERVER_NOUSE: 899, // 無用				
        SERVER_MAINTAIN: 998, // 維護中				
        SERVER_SHUTDOWN: 999, // 關機中				
        SERVER_NEED_UID: 1001, //需要UID				
        SERVER_NEED_LOGIN: 1002, //沒有玩家				
        SERVER_TOKEN_ERROR: 1003, //TOKEN 錯誤				
    };
    static LOGIN_RESULT_TYPE = {
        LOGIN_SUCCESS: 0, //登入成功
        LOGIN_FAIL: 1, // 登入失敗
        API_VERIFY_FAIL: 2001,   // TOKEN驗證失敗
        API_LOGIN_REPEAT_FAIL: 2002,    // 重複登入
    };
    static HEART_BEAT_STATE = {
        NOTIFY: 97, //SERVER 通知訊息
        MAINTAIN: 98, //SERVER 維護中
        CLOSE: 99, //SERVER 關閉
    };
    static StringKey = {
        MC_FEATURES_LEFT: "MC_FEATURES_LEFT",
        MC_FEATURES_RIGHT: "MC_FEATURES_RIGHT",
        FREE_GAME_NAME_STRING: "FREE_GAME_NAME_STRING",
    };

    static ShowDisplayValue: (value: number) => number = null;

    /**@ch 特色遊玩押注 */
    static FeatureBetValue = 10;

    static OnExit() {
        this.BgAudioId = -1;
        this.ShowDisplayValue = null;
    }

    /**@ch 線配置 - 記錄每條線涉及的位置索引 (0-14)
     * 盤面位置索引:
     *  0    3    6    9   12
     *  1    4    7   10   13
     *  2    5    8   11   14
     */
