9	/**@ch 牛仔事件常數 */
10	export const BONUS_GAME_COWBOY_EVENT = {
11	    /**牛仔進場，參數1:哪幾輪有小偷, 參數2: callback陣列（數量需與小偷輪數相同）*/
12	    ENTER: 'BONUS_GAME_COWBOY_ENTER',
13	    PLAY_SHOOT_ANIMATIONS: 'COWBOY_PLAY_SHOOT_ANIMATIONS',
