32	@ccclass('BonusGameCowboyController')
33	export class BonusGameCowboyController extends Component {
34	    @property({type: BaseSpine, tooltip: '牛仔 Spine'}) private m_CowboySkeleton: BaseSpine = null;
35	    
36	    @property({tooltip: "牛仔移動速度（單位/秒）"}) private m_moveSpeed: number = 900;
37	    //起始x座標
38	    @property({tooltip: "起始x座標"}) private m_startX: number = -40.69875;
39	    //目標x座標
40	    @property({tooltip: "目標x座標"}) private m_targetX: number = 1060.78625;
41	    //退場x座標
42	    @property({tooltip: "退場x座標"}) private m_leaveX: number = 2421.80125;
43	    
44	    private m_hasRegisteredEvents: boolean = false;
45	
46	    // ========== Lifecycle ==========
47	
48	    protected onLoad(): void {
49	        this.RegisterBonusGameCowboyEvents();
50	    }
51	
52	    protected onDestroy(): void {
53	        this.UnregisterBonusGameCowboyEvents();
54	    }
55	
56	    // ========== Event Register / Unregister ==========
57	
58	    private RegisterBonusGameCowboyEvents(): void {
59	        if (this.m_hasRegisteredEvents) {
60	            return;
61	        }
62	
63	        eventManager.Register(BONUS_GAME_COWBOY_EVENT.ENTER, this);
64	        eventManager.Register(BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS, this);
65	        eventManager.Register(BONUS_GAME_COWBOY_EVENT.LEAVE, this);
66	        eventManager.Register(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, this);
67	        eventManager.Register(BONUS_GAME_COWBOY_EVENT.SMILE, this);
68	        this.m_hasRegisteredEvents = true;
69	    }
70	
71	    private UnregisterBonusGameCowboyEvents(): void {
72	        if (!this.m_hasRegisteredEvents) {
73	            return;
74	        }
75	
76	        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.ENTER, this);
77	        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS, this);
78	        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.LEAVE, this);
79	        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, this);
80	        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.SMILE, this);
81	
82	        this.m_hasRegisteredEvents = false;
83	    }
84	
85	    // ========== Event Callback ==========
86	
87	    OnEvent(event: string, ...args: any[]): void {
88	        if (event === BONUS_GAME_COWBOY_EVENT.ENTER) {
89	            const callback = args?.[0] as () => void;
90	            this.HandleBonusGameCowboyEnter(callback);
91	        }
92	
93	        if (event === BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS) {
94	            const targetIndex = args?.[0] as BONUS_GAME_COWBOY_TARGET_INDEX;
95	            if (typeof targetIndex !== 'number' || targetIndex < BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT || targetIndex > BONUS_GAME_COWBOY_TARGET_INDEX.LEFT) {
96	                console.warn(`[BonusGameCowboyController] 無效的 targetIndex: ${args?.[0]}`);
97	                return;
98	            }
99	
100	            const callback = args?.[1] as () => void;
101	            void this.HandleBonusGameCowboyPlayShootAnimations(targetIndex, callback);
102	        }
103	
104	        if (event === BONUS_GAME_COWBOY_EVENT.LEAVE) {
105	            const callback = args?.[0] as () => void;
106	            this.HandleBonusGameCowboyLeave(callback);
107	        }
108	        if (event === BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS) {
109	            const isMiss = args?.[0] as boolean;
110	            const callback = args?.[1] as () => void;
111	            void this.HandleBonusGameCowboyPlayResultAnimations(isMiss, callback);
112	        }
113	
114	        if (event === BONUS_GAME_COWBOY_EVENT.SMILE) {
115	            const callback = args?.[0] as () => void;
116	            this.HandleBonusGameCowboySmile(callback);
117	        }
118	    }
119	
120	    // ========== Handlers ==========
121	
122	    private HandleBonusGameCowboyEnter(callback?: () => void): void {
123	        console.log('HandleBonusGameCowboyEnter');
124	        void this.PlayCowboyEnterToTargetNode(callback);
125	    }
126	
127	    private GetCowboySkeletons(): BaseSpine[] {
128	        const cowboySkeletons: BaseSpine[] = [];
129	        if (this.m_CowboySkeleton) {
130	            cowboySkeletons.push(this.m_CowboySkeleton);
131	        }
132	        
133	        return cowboySkeletons;
134	    }
135	
136	    private IsCowboySpineOpen(cowboySkeleton: BaseSpine): boolean {
137	        if (!cowboySkeleton) {
138	            return false;
139	        }
140	
141	        if (!cowboySkeleton.node.active) {
142	            return false;
143	        }
144	
145	        // BaseSpine.Spine 可能尚未綁定，視為不可播放
146	        if (!cowboySkeleton.Spine || !cowboySkeleton.Spine.node.active) {
147	            return false;
148	        }
149	
150	        return true;
151	    }
152	
153	    private PlayMoveAsync(cowboySkeleton: BaseSpine, fromX: number, toX: number, onComplete?: () => void): Promise<void> {
154	        // 若 spine 關閉則不播放、也不需要等待
155	        if (!this.IsCowboySpineOpen(cowboySkeleton)) {
156	            return Promise.resolve();
157	        }
158	
159	        // 跑步時確保 scaleX 為正（避免奔跑翻面造成表演怪異）
160	        const currentScale = cowboySkeleton.node.scale;
161	        cowboySkeleton.node.setScale(Math.abs(currentScale.x), currentScale.y, currentScale.z);
162	
163	        cowboySkeleton.PlayAnimation(COWBOY_ANIM.RUN, cowboySkeleton.Spine, true);
164	        cowboySkeleton.node.setPosition(
165	            fromX, 
166	            cowboySkeleton.node.getPosition().y, 
167	            cowboySkeleton.node.getPosition().z);
168	
169	        const targetPosition = new Vec3(
170	            toX, 
171	            cowboySkeleton.node.getPosition().y, 
172	            cowboySkeleton.node.getPosition().z);
173	        
174	
175	        const distance = Math.abs(this.m_targetX - this.m_startX);
176	        const moveTime = (this.m_moveSpeed > 0) ? (distance / this.m_moveSpeed) : 0;
177	
178	        return new Promise<void>((resolve) => {
179	            Tween.stopAllByTarget(cowboySkeleton.node);
180	            tween(cowboySkeleton.node)
181	                .to(moveTime, { position: targetPosition }, { easing: 'linear' })
182	                .call(() => {
183	                    if (onComplete) {
184	                        onComplete();
185	                    }
186	                    resolve();
187	                })
188	                .start();
189	        });
190	    }
191	
192	    private async PlayCowboyEnterToTargetNode(callback?: () => void): Promise<void> {
193	        const cowboySkeletons = this.GetCowboySkeletons();
194	        if (cowboySkeletons.length === 0) {
195	            return;
196	        }
197	
198	        const movePromises: Promise<void>[] = [];
199	
200	        // 橫版
201	        if (this.m_CowboySkeleton) {
202	            if (this.IsCowboySpineOpen(this.m_CowboySkeleton)) {
203	                movePromises.push(this.PlayMoveAsync(
204	                    this.m_CowboySkeleton,
205	                    this.m_startX,
206	                    this.m_targetX,
207	                    () => {
208	                        this.m_CowboySkeleton.PlayAnimation(COWBOY_ANIM.IDLE, this.m_CowboySkeleton.Spine, true);
209	                    }
210	                )
211	                );
212	            }
213	        }
214	
215	
216	        if (movePromises.length > 0) {
217	            await Promise.all(movePromises);
218	        }
219	        callback?.();
220	    }
221	
222	    private async HandleBonusGameCowboyPlayShootAnimations(targetIndex: BONUS_GAME_COWBOY_TARGET_INDEX, callback?: () => void): Promise<void> {
223	        //const targetName = BONUS_GAME_COWBOY_TARGET_INDEX[targetIndex];
224	        const shootAnimName = this.GetCowboyShootAnimName(targetIndex);
225	        const turnAnimName = this.GetCowboyTurnAnimName(shootAnimName);
226	
227	
228	        const cowboySkeletons = this.GetCowboySkeletons();
229	        if (cowboySkeletons.length === 0) {
230	            return;
231	        }
232	
233	        // LEFT 相關要翻面（scaleX 為負），RIGHT 相關保持正值
234	        const isLeft = (targetIndex === BONUS_GAME_COWBOY_TARGET_INDEX.LEFT || targetIndex === BONUS_GAME_COWBOY_TARGET_INDEX.LEFT_TOP);
235	        for (const skeleton of cowboySkeletons) {
236	            const currentScale = skeleton.node.scale;
237	            const absScaleX = Math.abs(currentScale.x);
238	            const newScaleX = isLeft ? -absScaleX : absScaleX;
239	            skeleton.node.setScale(newScaleX, currentScale.y, currentScale.z);
240	        }
241	
242	        await this.PlayCowboyTurnThenShootAsync(turnAnimName, shootAnimName);
243	        callback?.();
244	    }
245	
246	    private async HandleBonusGameCowboyPlayResultAnimations(isMiss: boolean, callback?: () => void): Promise<void> {
247	        const resultAnimName = this.GetCowboyShootResultAnimName(isMiss);
248	        const cowboySkeletons = this.GetCowboySkeletons();
249	        if (cowboySkeletons.length === 0) {
250	            return;
251	        }
252	        for (const skeleton of cowboySkeletons) {
253	            if (!this.IsCowboySpineOpen(skeleton)) {
254	                continue;
255	            }
256	            console.log('PlayResultAnimation', resultAnimName);
257	            if(isMiss == false)
258	            {
259	                this.scheduleOnce(() => {
260	                    AudioManager.Play(AudioManager.AudioClips.Thief_Shoot);
261	                }, 0.4);
262	            }
263	            
264	            if(isMiss)
265	            {
266	                skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
267	                this.scheduleOnce(() => {
268	                    skeleton.Spine.paused = true;
269	                }, 0.5);
270	                await Define.Wait(this, 0.5);
271	                
272	            }
273	            else
274	            {
275	                await skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
276	            }
277	            //skeleton.Spine.paused = false;
278	            //await Define.Wait(this, 0.3);
279	            await Define.Wait(this, 0.5);
280	            if(isMiss)
281	            {
282	                skeleton.Spine.paused = false;
283	                await skeleton.PlayAnimation(COWBOY_ANIM.MISS_TURN_TO_IDLE, skeleton.Spine, false);
284	                skeleton.PlayAnimation(COWBOY_ANIM.IDLE, skeleton.Spine, true);
285	            }
286	            else
287	            {
288	                
289	                // 倒播回去 
290	                const trackEntry = skeleton.Spine.setAnimation(0, COWBOY_ANIM.SUCCESS, false);
291	                const animation = skeleton.Spine.findAnimation(COWBOY_ANIM.SUCCESS);
292	                if (animation) {
293	                    trackEntry.trackTime = animation.duration * 0.5;
294	                    trackEntry.timeScale = -1;
295	                    
296	                    // 等待倒播完成
297	                    await new Promise<void>((resolve) => {
298	                        this.scheduleOnce(() => resolve(), trackEntry.trackTime);
299	                    });
300	                }
301	                skeleton.PlayAnimation(COWBOY_ANIM.IDLE, skeleton.Spine, true);
302	            }
303	        }
304	        callback?.();
305	    }
