307	    private HandleBonusGameCowboyLeave(callback?: () => void): void {
308	        console.log('HandleBonusGameCowboyLeave');
309	
310	        // 退場時固定面向正方向（避免前面射擊轉向導致 scaleX 為負）
311	        for (const skeleton of this.GetCowboySkeletons()) {
312	            if (!this.IsCowboySpineOpen(skeleton)) {
313	                continue;
314	            }
315	            const scale = skeleton.node.scale;
316	            skeleton.node.setScale(Math.abs(scale.x), scale.y, scale.z);
