318	
319	        void this.PlayCowboyLeaveToLeaveNode(callback);
320	    }
321	
322	    private async HandleBonusGameCowboySmile(callback?: () => void): Promise<void> {
323	        console.log('HandleBonusGameCowboySmile');
324	        const resultAnimName = "Idle_To_Smile";
325	        const cowboySkeletons = this.GetCowboySkeletons();
326	        if (cowboySkeletons.length === 0) {
327	            return;
328	        }
329	        for (const skeleton of cowboySkeletons) {
330	            if (!this.IsCowboySpineOpen(skeleton)) {
331	                continue;
332	            }
333	            console.log('PlayResultAnimation', resultAnimName);
334	
335	            this.scheduleOnce(() => {
336	                AudioManager.Play(AudioManager.AudioClips.BG_End_CowboyAction);
337	            }, 0.5);
338	            await skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
339	            
340	        }
341	        callback?.();
342	    }
343	
344	    // ========== Animation Helpers ==========
345	
346	    private GetCowboyShootAnimName(targetIndex: BONUS_GAME_COWBOY_TARGET_INDEX): string {
347	        // 依方向 enum 決定要播的射擊動畫（需要調整對應時改這裡即可）
348	        switch (targetIndex) {
349	            case BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT:
350	            case BONUS_GAME_COWBOY_TARGET_INDEX.LEFT:
351	                return COWBOY_ANIM.SHUT_BOTTOM;
352	
353	            case BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT_TOP:
354	            case BONUS_GAME_COWBOY_TARGET_INDEX.LEFT_TOP:
355	                return COWBOY_ANIM.SHUT_MIDDLE;
356	
357	            case BONUS_GAME_COWBOY_TARGET_INDEX.MIDDLE:
358	                return COWBOY_ANIM.SHUT_TOP;
359	
360	            default:
361	                return COWBOY_ANIM.SHUT_MIDDLE;
362	        }
363	    }
364	
365	    private GetCowboyTurnAnimName(shootAnimName: string): string {
366	        // 射擊前的轉向動畫命名規則：Shut_XXXX_Turn（XXXX = Top/Middle/Bottom）
367	        switch (shootAnimName) {
