386	                return COWBOY_ANIM.SHUT_BOTTOM_TURN_TO_IDLE;
387	
388	            case COWBOY_ANIM.SHUT_MIDDLE:
389	                return COWBOY_ANIM.SHUT_MIDDLE_TURN_TO_IDLE;
390	
391	            case COWBOY_ANIM.SHUT_TOP:
392	                return COWBOY_ANIM.SHUT_TOP_TURN_TO_IDLE;
