@ccclass('BonusGameCowboyController')
export class BonusGameCowboyController extends Component {
    @property({type: BaseSpine, tooltip: '牛仔 Spine'}) private m_CowboySkeleton: BaseSpine = null;

    @property({tooltip: "牛仔移動速度（單位/秒）"}) private m_moveSpeed: number = 900;
    //起始x座標
    @property({tooltip: "起始x座標"}) private m_startX: number = -40.69875;
    //目標x座標
    @property({tooltip: "目標x座標"}) private m_targetX: number = 1060.78625;
    //退場x座標
    @property({tooltip: "退場x座標"}) private m_leaveX: number = 2421.80125;

    private m_hasRegisteredEvents: boolean = false;

    // ========== Lifecycle ==========

    protected onLoad(): void {
        this.RegisterBonusGameCowboyEvents();
    }

    protected onDestroy(): void {
        this.UnregisterBonusGameCowboyEvents();
    }

    // ========== Event Register / Unregister ==========

    private RegisterBonusGameCowboyEvents(): void {
        if (this.m_hasRegisteredEvents) {
            return;
        }

        eventManager.Register(BONUS_GAME_COWBOY_EVENT.ENTER, this);
        eventManager.Register(BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS, this);
        eventManager.Register(BONUS_GAME_COWBOY_EVENT.LEAVE, this);
        eventManager.Register(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, this);
        eventManager.Register(BONUS_GAME_COWBOY_EVENT.SMILE, this);
        this.m_hasRegisteredEvents = true;
    }

    private UnregisterBonusGameCowboyEvents(): void {
        if (!this.m_hasRegisteredEvents) {
            return;
        }

        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.ENTER, this);
        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS, this);
        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.LEAVE, this);
        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, this);
        eventManager.UnRegister(BONUS_GAME_COWBOY_EVENT.SMILE, this);

        this.m_hasRegisteredEvents = false;
    }

    // ========== Event Callback ==========

    OnEvent(event: string, ...args: any[]): void {
        if (event === BONUS_GAME_COWBOY_EVENT.ENTER) {
            const callback = args?.[0] as () => void;
            this.HandleBonusGameCowboyEnter(callback);
        }

        if (event === BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS) {
            const targetIndex = args?.[0] as BONUS_GAME_COWBOY_TARGET_INDEX;
            if (typeof targetIndex !== 'number' || targetIndex < BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT || targetIndex > BONUS_GAME_COWBOY_TARGET_INDEX.LEFT) {
                console.warn(`[BonusGameCowboyController] 無效的 targetIndex: ${args?.[0]}`);
                return;
            }

            const callback = args?.[1] as () => void;
            void this.HandleBonusGameCowboyPlayShootAnimations(targetIndex, callback);
        }

        if (event === BONUS_GAME_COWBOY_EVENT.LEAVE) {
            const callback = args?.[0] as () => void;
            this.HandleBonusGameCowboyLeave(callback);
        }
        if (event === BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS) {
            const isMiss = args?.[0] as boolean;
            const callback = args?.[1] as () => void;
            void this.HandleBonusGameCowboyPlayResultAnimations(isMiss, callback);
        }

        if (event === BONUS_GAME_COWBOY_EVENT.SMILE) {
            const callback = args?.[0] as () => void;
            this.HandleBonusGameCowboySmile(callback);
        }
    }

    // ========== Handlers ==========

    private HandleBonusGameCowboyEnter(callback?: () => void): void {
        console.log('HandleBonusGameCowboyEnter');
        void this.PlayCowboyEnterToTargetNode(callback);
    }

    private GetCowboySkeletons(): BaseSpine[] {
        const cowboySkeletons: BaseSpine[] = [];
        if (this.m_CowboySkeleton) {
            cowboySkeletons.push(this.m_CowboySkeleton);
        }

        return cowboySkeletons;
    }

    private IsCowboySpineOpen(cowboySkeleton: BaseSpine): boolean {
        if (!cowboySkeleton) {
            return false;
        }

        if (!cowboySkeleton.node.active) {
            return false;
        }

        // BaseSpine.Spine 可能尚未綁定，視為不可播放
        if (!cowboySkeleton.Spine || !cowboySkeleton.Spine.node.active) {
            return false;
        }

        return true;
    }

    private PlayMoveAsync(cowboySkeleton: BaseSpine, fromX: number, toX: number, onComplete?: () => void): Promise<void> {
        // 若 spine 關閉則不播放、也不需要等待
        if (!this.IsCowboySpineOpen(cowboySkeleton)) {
            return Promise.resolve();
        }

        // 跑步時確保 scaleX 為正（避免奔跑翻面造成表演怪異）
        const currentScale = cowboySkeleton.node.scale;
        cowboySkeleton.node.setScale(Math.abs(currentScale.x), currentScale.y, currentScale.z);

        cowboySkeleton.PlayAnimation(COWBOY_ANIM.RUN, cowboySkeleton.Spine, true);
        cowboySkeleton.node.setPosition(
            fromX, 
            cowboySkeleton.node.getPosition().y, 
            cowboySkeleton.node.getPosition().z);

        const targetPosition = new Vec3(
            toX, 
            cowboySkeleton.node.getPosition().y, 
            cowboySkeleton.node.getPosition().z);


        const distance = Math.abs(this.m_targetX - this.m_startX);
        const moveTime = (this.m_moveSpeed > 0) ? (distance / this.m_moveSpeed) : 0;

        return new Promise<void>((resolve) => {
            Tween.stopAllByTarget(cowboySkeleton.node);
            tween(cowboySkeleton.node)
                .to(moveTime, { position: targetPosition }, { easing: 'linear' })
                .call(() => {
                    if (onComplete) {
                        onComplete();
                    }
                    resolve();
                })
                .start();
        });
    }

    private async PlayCowboyEnterToTargetNode(callback?: () => void): Promise<void> {
        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }

        const movePromises: Promise<void>[] = [];

        // 橫版
        if (this.m_CowboySkeleton) {
            if (this.IsCowboySpineOpen(this.m_CowboySkeleton)) {
                movePromises.push(this.PlayMoveAsync(
                    this.m_CowboySkeleton,
                    this.m_startX,
                    this.m_targetX,
                    () => {
                        this.m_CowboySkeleton.PlayAnimation(COWBOY_ANIM.IDLE, this.m_CowboySkeleton.Spine, true);
                    }
                )
                );
            }
        }


        if (movePromises.length > 0) {
            await Promise.all(movePromises);
        }
        callback?.();
    }

    private async HandleBonusGameCowboyPlayShootAnimations(targetIndex: BONUS_GAME_COWBOY_TARGET_INDEX, callback?: () => void): Promise<void> {
        //const targetName = BONUS_GAME_COWBOY_TARGET_INDEX[targetIndex];
        const shootAnimName = this.GetCowboyShootAnimName(targetIndex);
        const turnAnimName = this.GetCowboyTurnAnimName(shootAnimName);


        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }

        // LEFT 相關要翻面（scaleX 為負），RIGHT 相關保持正值
        const isLeft = (targetIndex === BONUS_GAME_COWBOY_TARGET_INDEX.LEFT || targetIndex === BONUS_GAME_COWBOY_TARGET_INDEX.LEFT_TOP);
        for (const skeleton of cowboySkeletons) {
            const currentScale = skeleton.node.scale;
            const absScaleX = Math.abs(currentScale.x);
            const newScaleX = isLeft ? -absScaleX : absScaleX;
            skeleton.node.setScale(newScaleX, currentScale.y, currentScale.z);
        }

        await this.PlayCowboyTurnThenShootAsync(turnAnimName, shootAnimName);
        callback?.();
    }

    private async HandleBonusGameCowboyPlayResultAnimations(isMiss: boolean, callback?: () => void): Promise<void> {
        const resultAnimName = this.GetCowboyShootResultAnimName(isMiss);
        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }
        for (const skeleton of cowboySkeletons) {
            if (!this.IsCowboySpineOpen(skeleton)) {
                continue;
            }
            console.log('PlayResultAnimation', resultAnimName);
            if(isMiss == false)
            {
                this.scheduleOnce(() => {
                    AudioManager.Play(AudioManager.AudioClips.Thief_Shoot);
                }, 0.4);
            }

            if(isMiss)
            {
                skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
                this.scheduleOnce(() => {
                    skeleton.Spine.paused = true;
                }, 0.5);
                await Define.Wait(this, 0.5);

            }
            else
            {
                await skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
            }
            //skeleton.Spine.paused = false;
            //await Define.Wait(this, 0.3);
            await Define.Wait(this, 0.5);
            if(isMiss)
            {
                skeleton.Spine.paused = false;
                await skeleton.PlayAnimation(COWBOY_ANIM.MISS_TURN_TO_IDLE, skeleton.Spine, false);
                skeleton.PlayAnimation(COWBOY_ANIM.IDLE, skeleton.Spine, true);
            }
            else
            {

                // 倒播回去 
                const trackEntry = skeleton.Spine.setAnimation(0, COWBOY_ANIM.SUCCESS, false);
                const animation = skeleton.Spine.findAnimation(COWBOY_ANIM.SUCCESS);
                if (animation) {
                    trackEntry.trackTime = animation.duration * 0.5;
                    trackEntry.timeScale = -1;

                    // 等待倒播完成
                    await new Promise<void>((resolve) => {
                        this.scheduleOnce(() => resolve(), trackEntry.trackTime);
                    });
                }
                skeleton.PlayAnimation(COWBOY_ANIM.IDLE, skeleton.Spine, true);
            }
        }
        callback?.();
    }

    private HandleBonusGameCowboyLeave(callback?: () => void): void {
        console.log('HandleBonusGameCowboyLeave');

        // 退場時固定面向正方向（避免前面射擊轉向導致 scaleX 為負）
        for (const skeleton of this.GetCowboySkeletons()) {
            if (!this.IsCowboySpineOpen(skeleton)) {
                continue;
            }
            const scale = skeleton.node.scale;
            skeleton.node.setScale(Math.abs(scale.x), scale.y, scale.z);
        }

        void this.PlayCowboyLeaveToLeaveNode(callback);
    }

    private async HandleBonusGameCowboySmile(callback?: () => void): Promise<void> {
        console.log('HandleBonusGameCowboySmile');
        const resultAnimName = "Idle_To_Smile";
        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }
        for (const skeleton of cowboySkeletons) {
            if (!this.IsCowboySpineOpen(skeleton)) {
                continue;
            }
            console.log('PlayResultAnimation', resultAnimName);

            this.scheduleOnce(() => {
                AudioManager.Play(AudioManager.AudioClips.BG_End_CowboyAction);
            }, 0.5);
            await skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);

        }
        callback?.();
    }

    // ========== Animation Helpers ==========

    private GetCowboyShootAnimName(targetIndex: BONUS_GAME_COWBOY_TARGET_INDEX): string {
        // 依方向 enum 決定要播的射擊動畫（需要調整對應時改這裡即可）
        switch (targetIndex) {
            case BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT:
            case BONUS_GAME_COWBOY_TARGET_INDEX.LEFT:
                return COWBOY_ANIM.SHUT_BOTTOM;

            case BONUS_GAME_COWBOY_TARGET_INDEX.RIGHT_TOP:
            case BONUS_GAME_COWBOY_TARGET_INDEX.LEFT_TOP:
                return COWBOY_ANIM.SHUT_MIDDLE;

            case BONUS_GAME_COWBOY_TARGET_INDEX.MIDDLE:
                return COWBOY_ANIM.SHUT_TOP;

            default:
                return COWBOY_ANIM.SHUT_MIDDLE;
        }
    }

    private GetCowboyTurnAnimName(shootAnimName: string): string {
        // 射擊前的轉向動畫命名規則：Shut_XXXX_Turn（XXXX = Top/Middle/Bottom）
        switch (shootAnimName) {
            case COWBOY_ANIM.SHUT_BOTTOM:
                return COWBOY_ANIM.SHUT_BOTTOM_TURN;

            case COWBOY_ANIM.SHUT_MIDDLE:
                return COWBOY_ANIM.SHUT_MIDDLE_TURN;

            case COWBOY_ANIM.SHUT_TOP:
                return COWBOY_ANIM.SHUT_TOP_TURN;

            default:
                return COWBOY_ANIM.SHUT_MIDDLE_TURN;
        }
    }

    private GetCowboyTurnToIdleAnimName(shootAnimName: string): string {
        // 射擊後的轉回待機轉身動畫：Shut_XXXX_TurntoIdle（XXXX = Top/Middle/Bottom）
        switch (shootAnimName) {
            case COWBOY_ANIM.SHUT_BOTTOM:
                return COWBOY_ANIM.SHUT_BOTTOM_TURN_TO_IDLE;

            case COWBOY_ANIM.SHUT_MIDDLE:
                return COWBOY_ANIM.SHUT_MIDDLE_TURN_TO_IDLE;

            case COWBOY_ANIM.SHUT_TOP:
                return COWBOY_ANIM.SHUT_TOP_TURN_TO_IDLE;

            default:
                return COWBOY_ANIM.SHUT_MIDDLE_TURN_TO_IDLE;
        }
    }

    private GetCowboyShootResultAnimName(isMiss: boolean): string {
        return isMiss ? COWBOY_ANIM.MISS : COWBOY_ANIM.SUCCESS;
    }

    private async PlayCowboyTurnThenShootAsync(turnAnimName: string, shootAnimName: string): Promise<void> {
        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }

        //const resultAnimName = this.GetCowboyShootResultAnimName(shootAnimName);
        const animationPromises: Promise<void>[] = [];

        for (const skeleton of cowboySkeletons) {
            if (!this.IsCowboySpineOpen(skeleton)) {
                continue;
            }

            animationPromises.push((async () => {
                await skeleton.PlayAnimation(turnAnimName, skeleton.Spine, false);
                await skeleton.PlayAnimation(shootAnimName, skeleton.Spine, false);
                const turnToIdleAnimName = this.GetCowboyTurnToIdleAnimName(shootAnimName);
                await skeleton.PlayAnimation(turnToIdleAnimName, skeleton.Spine, false);

                // 轉身回來後，比成功/失敗動作，再回到待機
                //await skeleton.PlayAnimation(resultAnimName, skeleton.Spine, false);
                skeleton.PlayAnimation(COWBOY_ANIM.IDLE, skeleton.Spine, true);
            })());
        }

        // if (animationPromises.length > 0) {
        //     await Promise.all(animationPromises);
        // }
    }

    private async PlayCowboyLeaveToLeaveNode(callback?: () => void): Promise<void> {
        const cowboySkeletons = this.GetCowboySkeletons();
        if (cowboySkeletons.length === 0) {
            return;
        }

        const movePromises: Promise<void>[] = [];

        // 橫版
        if (this.m_CowboySkeleton) {
            if (this.IsCowboySpineOpen(this.m_CowboySkeleton)) {
                movePromises.push(this.PlayMoveAsync(
                    this.m_CowboySkeleton,
                    this.m_targetX,
                    this.m_leaveX,

                )
                );
            }
        }


        if (movePromises.length > 0) {
            await Promise.all(movePromises);
        }
        callback?.();
    }


}

