784	    /**
785	     * 射擊指定的目標
786	     */
787	    private async ShootTarget(targetIndex: number): Promise<void> 
788	    {
789	        let currentDatas = this.GetCurrentStageDatas();
790	        let data = currentDatas[targetIndex];
791	
792	        if (!data || data.state !== TargetState.IDLE) 
793	        {
794	            error(`[BonusGameController] 無效的目標或目標已被射擊: ${targetIndex}`);
795	            return;
796	        }
797	
798	        // 暫停閒置計時器（射擊過程中）
799	        this.StopIdleTimer();
800	
801	        // 暫停問號輪播
802	        this.StopQuestionMarkLoop();
803	
804	        // 禁用所有其他 PickItem
805	        this.SetAllPickItemsClickable(false);
806	
807	        
808	        // 更新目標狀態
809	        data.state = TargetState.REVEALING;
810	        log(`[BonusGameController] 取值: ${this.m_currentStage+1}, ${this.m_shootCount}`);
811	        data.reward = this.m_bonusGameState.stages[this.m_currentStage+1].rewards[this.m_shootCount];
812	        log(`[BonusGameController] 射擊目標: ${targetIndex}, 資料: ${data.reward?.type}, ${data.reward?.value}`);
813	        // 獲取對應的 PickItem 並播放射擊動畫
814	        let currentItems = this.GetCurrentStagePickItems();
815	        const pickItem = currentItems[targetIndex];
816	
817	        //Common.SetLockOrientation(true);
818	        // 播放牛仔射擊動畫
819	        await this.CowboyPlayShootAnimations(pickItem?.GetShootDirection(this.m_bonusGameDirection));
820	
821	        // 禁用其他目標
822	        for(let i = 0; i < currentItems.length; i++)
823	        {
824	            if(i !== targetIndex)
825	            {
826	                currentItems[i].SetClickable(false);
827	            }
828	            
829	        }
830	
831	        // 射擊目標
832	        if (pickItem) 
833	        {
834	            await pickItem.Shoot(data.reward);
835	            this.m_totalScore += data.reward.value;
836	            if(this.m_totalScore >= this.m_maxWin)
837	            {
838	                this.m_totalScore = this.m_maxWin;
839	            }
840	            this.UpdateTotalScore();
841	            newBottombarManager.SetWinValue(this.m_preRoundWin + this.m_totalScore);
842	            this.m_shootCount++;
843	            
844	        }
845	
846	        // 處理獎勵
847	        await this.RevealTarget(data);
848	
849	        //Common.SetLockOrientation(false);
850	
851	
852	        // 播放牛仔結果動畫
853	        //let isMiss = data.reward?.type === protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_MISS;
854	        await this.CowboyPlayResultAnimations(data);
