1233	     */
1234	    private InitializeTransitionMask(): void 
1235	    {
1236	        if (!this.m_transitionMask) {
1237	            warn('[BonusGameController] 轉場遮罩節點未設定');
1238	            return;
1239	        }
1240	
1241	        // 獲取或添加 UIOpacity 組件
1242	        this.m_transitionMaskOpacity = this.m_transitionMask.getComponent(UIOpacity);
1243	        if (!this.m_transitionMaskOpacity) {
