1245	        }
1246	
1247	        // 初始設為完全透明
1248	        this.m_transitionMaskOpacity.opacity = 0;
1249	        
1250	        // 確保遮罩在最上層但初始不顯示
1251	        this.m_transitionMask.active = false;
1252	
1253	        // 確保有 Sprite 組件用於顯示黑色
