1260	    /**
1261	     * 播放轉場特效
1262	     * @param callback 轉場完成後的回調（在黑章最濃時執行）
1263	     * @returns Promise，在整個轉場動畫完成後 resolve
1264	     */
1265	    private PlayTransitionEffect(callback?: () => void): Promise<void> 
1266	    {
1267	        return new Promise<void>((resolve) => {
1268	            if (!this.m_transitionMask || !this.m_transitionMaskOpacity) {
1269	                warn('[BonusGameController] 轉場遮罩未初始化');
1270	                if (callback) callback();
1271	                resolve();
1272	                return;
1273	            }
1274	
1275	            if (this.m_isTransitioning) {
1276	                warn('[BonusGameController] 轉場特效正在進行中');
1277	                resolve();
1278	                return;
1279	            }
1280	
1281	            this.m_isTransitioning = true;
1282	            this.m_transitionMask.active = true;
1283	
1284	            log('[BonusGameController] 播放轉場特效');
1285	            // 淡入（變黑）-> 停留 -> 執行回調 -> 淡出（變透明）
1286	            tween(this.m_transitionMaskOpacity)
1287	                // 淡入：0 -> 255
1288	                .to(this.m_transitionFadeInDuration, { opacity: 255 })
1289	                // 停留
1290	                .delay(this.m_transitionHoldDuration)
1291	                // 在黑章最濃時執行回調（切換場景）
1292	                .call(() => {
1293	                    if (callback) {
1294	                        callback();
1295	                    }
1296	                })
1297	                // 淡出：255 -> 0
1298	                .to(this.m_transitionFadeOutDuration, { opacity: 0 })
1299	                // 完成
1300	                .call(() => {
1301	                    this.m_transitionMask.active = false;
1302	                    this.m_isTransitioning = false;
1303	                    log('[BonusGameController] 轉場特效完成');
1304	                    resolve();
1305	                })
1306	                .start();
1307	        });
1308	    }
