import { _decorator, Component, Node, UIOpacity, tween, Color, Sprite, log, error, warn, screen, Button, Label } from 'cc';
import { eventManager, newBottombarManager } from 'db://astarte-framework/Managers';
import { BONUS_GAME_EVENT } from '../BonusGame/BonusGame_Define';
import { tools, Define } from "db://astarte-framework/utilis";
import { Common } from "../Common/Common";
import { PickItem, TargetState } from './PickItem';
import { StageUI } from './StageUI';
import { BONUS_GAME_COWBOY_EVENT, BONUS_GAME_COWBOY_TARGET_INDEX, BONUS_GAME_COWBOY_RESULT } from '../BonusGameCowboyController';
import protocol from "@igs-arcade-division-rd2/uk_746_far_west_proto/ar2fwProto.js";
import { InLoopOutSpine } from '../Spine/InLoopOutSpine';
import GameView from '../GameView';
import { AudioManager } from "../Audio/AudioManager";
import { FocusMask } from './FocusMask';
const { ccclass, property } = _decorator;

// 遊戲方向
export enum BonusGameDirection
{
    HORIZONTAL = 0,
    VERTICAL = 1
}

/** Bonus Game 關卡編號 */
enum BonusStage 
{
    STAGE_1 = 0,
    STAGE_2 = 1,
    STAGE_3 = 2
}



/** 單個目標數據 */
interface TargetData 
{
    index: number;
    state: TargetState;
    reward: protocol.ar2fwProto.IBonusGameReward | null;
}

@ccclass('BonusGameController')
export class BonusGameController extends Component 
{
    @property({ type: Node, tooltip: 'Bonus Game 顯示根節點' })
    private m_displayRoot: Node | null = null;

    @property({ type: Button, tooltip: 'Bonus Game 開始按鈕' })
    private m_startButton: Button | null = null;

    @property({ type: [StageUI], tooltip: '關卡UI' })
    private m_stageUIs: StageUI[] = [];

    // 轉場特效相關
    @property({ type: Node, tooltip: '黑章轉場遮罩（黑色全屏遮罩）' })
    private m_transitionMask: Node | null = null;

    @property({ type: FocusMask, tooltip: '焦點轉場遮罩' })
    private m_transitionFocusMask: FocusMask | null = null;

    @property({ tooltip: '轉場淡入時間（秒）', slide: true, min: 0, max: 2 })
    private m_transitionFadeInDuration = 0.5;

    @property({ tooltip: '轉場淡出時間（秒）', slide: true, min: 0, max: 2 })
    private m_transitionFadeOutDuration = 0.5;

    @property({ tooltip: '轉場黑章停留時間（秒）', slide: true, min: 0, max: 2 })
    private m_transitionHoldDuration = 0.3;

    @property({ type: Node, tooltip: '宣告根節點' })
    private m_OPRoot: Node | null = null;

    @property({ type: InLoopOutSpine, tooltip: '結算根節點' })
    private m_opSpine: InLoopOutSpine | null = null;

    @property({ type: Node, tooltip: '子彈根節點' })
    private m_bulletRoot: Node | null = null;

    @property({ tooltip: '問號輪播間隔時間（秒）', slide: true, min: 0, max: 3 })
    private m_questionMarkInterval = 1;

    @property({ type: Sprite, tooltip: 'Bonus Game title sprite' })
    private m_titleSprite1: Sprite | null = null;

    @property({ type: Sprite, tooltip: 'Bonus Game title sprite' })
    private m_titleSprite2: Sprite | null = null;

    @property({ type: Node, tooltip: '牛仔根節點' })
    private m_cowboyRoot: Node | null = null;

    @property({ type: GameView, tooltip: 'GameView' })
    private m_gameView: GameView = null;

    //宣告自動進入秒數
    @property({ type: Number,tooltip: '宣告自動進入秒數'})
    private m_opAutoEnterTime: number = 3;

    //自動遊玩秒數
    @property({ type: Number,tooltip: '自動遊玩秒數'})
    private m_autoPlayTime: number = 10;

    //自動遊玩秒數Root
    @property({ type: Node, tooltip: '自動遊玩秒數Root' })
    private m_autoPlayTimeRoot: Node | null = null;

    //自動遊玩秒數Label
    @property({ type: Label, tooltip: '自動遊玩秒數Label' })
    private m_autoPlayTimeLabel: Label | null = null;

    //自動遊玩資訊
    @property({ type: Sprite, tooltip: '自動遊玩資訊' })
    private m_autoPlayInfoSprite: Sprite | null = null;

    // ========== 遊戲狀態 ==========
    private m_isGamePlaying = false;
    private m_currentStage: BonusStage = BonusStage.STAGE_1;
    private m_bulletCount: number = 0;          // 剩餘MISS機會
    private m_bonusGameState: protocol.ar2fwProto.IBonusGameState | null = null;
    private m_isLandscape: boolean = false;
    // ========== Cutscene 狀態 ==========
    // 各關卡目標數據
    private m_stage1Datas: TargetData[] = [];
    private m_stage2Datas: TargetData[] = [];
    private m_stage3Datas: TargetData[] = [];

    // 新增：轉場狀態
    private m_isTransitioning: boolean = false;
    private m_transitionMaskOpacity: UIOpacity | null = null;

    // 可射擊的目標索引池（尚未射擊的目標）
    private m_shootCount: number = 0;
    private m_showQuestionMarkIndex: number = 0;

    private m_totalScore: number = 0;


    // 開始遊戲回調
    private m_startGameCallback: (() => void) | null = null;

    // 回調函數
    private m_gameCompleteCallback: (() => void) | null = null;

    private m_bonusGameDirection: BonusGameDirection = BonusGameDirection.HORIZONTAL;

    // 閒置自動遊玩相關
    private m_isAutoPlay: boolean = false; // 是否開啟閒置自動遊玩
    private m_idleElapsedTime: number = 0;  // 已閒置時間
    private m_maxWin: number = 9999999999999999999999999999999999;
    private m_preRoundWin: number = 0;
    private m_isReplay: boolean = false;
    private m_seedTargets: number[] = [];

    protected onEnable(): void 
    {
        this.RegisterBonusGameEvents();
    }

    protected start(): void
    {

        this.InitializeTransitionMask();
        // 初始化 title sprite 多國
        const bonusSprite = Common.GetSpriteInCommonText("BonusText");
        if(this.m_titleSprite1)
        {
            log(`[BonusGameController] 設置 title sprite 1: ${bonusSprite}`);
            this.m_titleSprite1.spriteFrame = bonusSprite;
        }

        const gameSprite = Common.GetSpriteInCommonText("GameText");
        if(this.m_titleSprite2)
        {
            log(`[BonusGameController] 設置 title sprite 2: ${gameSprite}`);
            this.m_titleSprite2.spriteFrame = gameSprite;
        }

        const autoPlayInfoSprite = Common.GetSpriteInCommonText("txt3");
        if(this.m_autoPlayInfoSprite)
        {
            log(`[BonusGameController] 設置自動遊玩資訊: ${autoPlayInfoSprite}`);
            this.m_autoPlayInfoSprite.spriteFrame = autoPlayInfoSprite;
        }
    }

    protected onDisable(): void 
    {
        this.UnregisterBonusGameEvents();

        // 確保清理閒置計時器
        this.StopIdleTimer();
    }

    private RegisterBonusGameEvents(): void 
    {
        eventManager.Register(BONUS_GAME_EVENT.SHOW_BONUS_OP, this);
        eventManager.Register(BONUS_GAME_EVENT.PLAY_BONUS_GAME, this);
        eventManager.Register(BONUS_GAME_EVENT.TARGET_SHOOT,this);
    }

    private UnregisterBonusGameEvents(): void 
    {
        eventManager.UnRegister(BONUS_GAME_EVENT.SHOW_BONUS_OP, this);
        eventManager.UnRegister(BONUS_GAME_EVENT.PLAY_BONUS_GAME, this);
        eventManager.UnRegister(BONUS_GAME_EVENT.TARGET_SHOOT,this);
    }

    public OnEvent(event: string, ...args: any[]): void 
    {
        switch (event) 
        {
            case BONUS_GAME_EVENT.SHOW_BONUS_OP: 
            {
                const callback = args?.[0];
                this.OnShowBonusOP(callback);     
                break;
            }

            case BONUS_GAME_EVENT.PLAY_BONUS_GAME: 
            {
                const bonusGameState = args?.[0];
                const maxWin = args?.[1];
                this.m_preRoundWin = args?.[2];
                const callback = args?.[3];

                this.m_maxWin = maxWin;
                log(`[BonusGameController] 設置最大獎金: ${this.m_maxWin}`);
                this.OnShow(bonusGameState, callback);
                break;
            }

            case BONUS_GAME_EVENT.TARGET_SHOOT:
            {
                const targetIndex = args?.[0];
                this.ResetIdleTimer();
                this.OnPlayerShoot(targetIndex);
                break;
            }
            default:
                break;
        }
    }
    // ========== 初始化和顯示 ==========
    onLoad() 
    {
        log("bonus game controller onLoad");
        this.CheckBonusGameDirection();
        tools.AddOnRotationCb( () => 
        {
            if(this.m_isGamePlaying && !this.m_gameView.IsLockRotation)
            {
                this.OnRotation();
            }


        });



        if (this.m_startButton) 
        {
            log('[BonusGameController] 開始按鈕註冊事件');
            this.m_startButton.node?.on(Button.EventType.CLICK, this.OnStartButtonClick, this);
        }
    }




    /**
     * 開始問號輪播
     */
    private StartQuestionMarkLoop(): void
    {
        this.unschedule(this.PlayQuestionMarkAnim);
        this.schedule(this.PlayQuestionMarkAnim, this.m_questionMarkInterval);
    }

    private PlayQuestionMarkAnim(): void
    {
        log(`[BonusGameController] 問號輪播 `);
        const currentItems = this.m_stageUIs[this.m_currentStage].GetPickItems();
        AudioManager.Play(AudioManager.AudioClips.BG_Tip);
        for(let i = 0; i < currentItems.length; i++)
        {
            const item = currentItems[i];
            if(item && item.IsCanShowQuestionMark())
            {
                item.PlayQuestionMarkAnimation();
            }
        }

        /*
            const item = currentItems[this.m_showQuestionMarkIndex];


            // 如果这个 item 可以显示问号，就播放动画
            if(item && item.IsCanShowQuestionMark())
            {
                AudioManager.Play(AudioManager.AudioClips.BG_Tip);
                // 等待动画播放完成
                yield item.PlayQuestionMarkAnimation();

                // 动画播完后等待间隔时间
                yield this.WaitForSeconds(this.m_questionMarkInterval);
            }
            else
            {
                // 动画播完后等待间隔时间
                yield this.WaitForSeconds(this.m_questionMarkInterval);
            }

            // 移动到下一个
            this.m_showQuestionMarkIndex++;
            */

    }



    /**
     * 停止問號輪播
     */
    private StopQuestionMarkLoop(): void
    {
        log(`[BonusGameController] 停止問號輪播`);
        this.unschedule(this.PlayQuestionMarkAnim);
    }




    private OnStartButtonClick(): void 
    {
        log('[BonusGameController] 開始按鈕點擊');
        this.unschedule(this.autoClickCallback);
        this.m_startButton.interactable = false;
        log('[BonusGameController] 播放BGPanel_Out音效');
        AudioManager.Play(AudioManager.AudioClips.BGPanel_Out);
        this.m_opSpine?.PlayOut(-1, ()=>{
            if (this.m_OPRoot) 
            {
                this.m_OPRoot.active = false;
            }
            this.m_startGameCallback?.();
            this.m_startGameCallback = null;
        });



    }

    private CheckBonusGameDirection(): void
    {
        log(`[BonusGameController] 檢查遊戲方向`);
        // 取得螢幕寬高
        let size = screen.windowSize;
        // 判斷橫版
        this.m_isLandscape = size.width > size.height;
        if(this.m_isLandscape)
        {
            this.m_bonusGameDirection = BonusGameDirection.HORIZONTAL;
        }
        else
        {
            this.m_bonusGameDirection = BonusGameDirection.VERTICAL;
        }
    }

    /**@ch 裝置旋轉 */
    async OnRotation() 
    {
        log('[BonusGameController] 裝置旋轉');
        this.CheckBonusGameDirection();
        this.UpdateBulletCountUI(this.m_bulletCount);
        for (const stageUI of this.m_stageUIs) 
        {
            stageUI.UpdateRotation(this.m_isLandscape);
        }


        //先復原所有的問號根節點
        for(let i = 0; i < this.GetCurrentStagePickItems().length; i++)
        {
            this.GetCurrentStagePickItems()[i].ResetQuestmarkRoot();
        }

        await Define.Wait(this, 0.1);

        //等動畫更新問號位置後再移動到問號根節點
        for(let i = 0; i < this.GetCurrentStagePickItems().length; i++)
        {
            this.GetCurrentStagePickItems()[i].SetToQuestionMarkRoot();
        }
        //this.m_gameView.IsLockRotation = false;
    }


    private autoClickCallback(): void {
        this.OnStartButtonClick();
    }

    public  OnShowBonusOP(callback: () => void): void
    {
        this.scheduleOnce(this.autoClickCallback, this.m_opAutoEnterTime);
        this.m_OPRoot.active = true;
        this.m_startButton.interactable = true;
        AudioManager.PlayBackGround(AudioManager.AudioClips.BGPanel_BGM);
        AudioManager.Play(AudioManager.AudioClips.BGPanel_In);
        this.m_opSpine?.Stop();
        this.m_opSpine?.PlayInLoop(()=>{},false);


        if (this.m_displayRoot) 
        {
            this.m_displayRoot.active = true;
        }

        this.m_startGameCallback = callback;

    }

    /**
     * 顯示 Bonus Game
     * @param bonusGameState 從伺服器獲取的 Bonus Game 狀態資料
     * @param callback 遊戲結束回調
     */
    public async OnShow(bonusGameState: protocol.ar2fwProto.IBonusGameState, callback: () => void): Promise<void> 
    {
        //判斷是否是重播
        //console.log(`[BonusGameController] HAS_REPLAY: ${Define.HAS_REPLAY}`);
        this.m_isReplay = Define.HAS_REPLAY !== null;
        //this.m_isReplay = true;

        //檢查遊戲方向
        this.CheckBonusGameDirection();

        // 顯示子彈根節點
        if (this.m_bulletRoot) 
        {
            this.m_bulletRoot.active = true;
        }
        if (this.m_cowboyRoot) 
        {
            this.m_cowboyRoot.active = true;
        }
        this.m_bonusGameState = bonusGameState;
        this.m_gameCompleteCallback = callback;

        // 初始化遊戲狀態
        this.m_bulletCount = bonusGameState.bulletCount || 0;
        this.m_totalScore = 0;
        this.m_currentStage = BonusStage.STAGE_1;
        this.m_isGamePlaying = false;
        this.m_shootCount = 0;
        this.m_showQuestionMarkIndex = 0;

        // 初始化各關卡目標數據
        this.InitializeStage();

        // 更新UI
        this.UpdateBulletCountUI(this.m_bulletCount);
        this.ShowCurrentStage();

        // 顯示根節點
        if (this.m_displayRoot) 
        {
            this.m_displayRoot.active = true;
        }

        this.m_gameView.IsLockRotation = true;
        // 播放開場淡入效果
        await this.FadeInTransition();

        AudioManager.Play(AudioManager.AudioClips.BG_Run);
        await this.CowboyEnter();

        this.StartGameplay();
        this.m_gameView.IsLockRotation = false;
    }

    private CowboyEnter(): Promise<void>
    {
        log('[BonusGameController] 牛仔進場');
        return new Promise<void>(async (resolve) => 
        {    
            eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.ENTER, ()=>
                {
                    resolve();
                });

        });
    }

    private CowboySmile(): Promise<void>
    {
        log('[BonusGameController] 牛仔微笑');
        return new Promise<void>(async (resolve) => 
        {    
            eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.SMILE, ()=>
                {
                    resolve();
                });
        });
    }

    private CowboyLeave(): Promise<void>
    {
        log('[BonusGameController] 牛仔退場');
        return new Promise<void>(async (resolve) => 
        {    
            eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.LEAVE, ()=>
                {
                    log('[BonusGameController] 牛仔退場完成');
                    resolve();
                });
        });
    }

    private CowboyPlayShootAnimations( targetIndex: BONUS_GAME_COWBOY_TARGET_INDEX ): Promise<void>
    {
        log(`[BonusGameController] 播放牛仔射擊動畫: ${targetIndex}`);
        return new Promise<void>(async (resolve) => 
        {    
            eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.PLAY_SHOOT_ANIMATIONS, 
                targetIndex,  ()=>
                {
                    this.scheduleOnce(() => {
                        resolve();
                    }, 0.5);
                });
        });
    }

    private CowboyPlayResultAnimations( data: TargetData ): Promise<void>
    {
        log(`[BonusGameController] 播放牛仔結果動畫: ${data.reward.type}`);
        return new Promise<void>(async (resolve) => 
        {    
            const rewardType = data.reward.type;
            switch(rewardType)
            {
                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_MISS:
                    eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, true, ()=>
                        {
                            resolve();
                        });
                    break;
                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_TARGET_SYMBOL:
                    eventManager.Dispatch(BONUS_GAME_COWBOY_EVENT.PLAY_RESULT_ANIMATIONS, false, ()=>
                        {
                            resolve();
                        });
                    break;
                default:
                    resolve();
                    break;
            }


        });
    }

    /**
     * 初始化各關卡的目標數據
     */
    private InitializeStage(): void 
    {

        // 關卡1
        this.m_stage1Datas = this.CreateTargetDataArray(
            this.m_stageUIs[0].GetPickItemNum()
        );

        // 關卡2
        this.m_stage2Datas = this.CreateTargetDataArray(
            this.m_stageUIs[1].GetPickItemNum()
        );

        // 關卡3
        this.m_stage3Datas = this.CreateTargetDataArray(
            this.m_stageUIs[2].GetPickItemNum()
        );

        // 初始化 PickItem
        this.InitializePickItems();

        // 初始化分數
        this.InitializeScore();
    }

    /**
     * 初始化 PickItem 物件
     */
    private InitializePickItems(): void 
    {
        log('[BonusGameController] 初始化 PickItem');
        for (let i = 0; i < this.m_stageUIs.length; i++) 
        {
            this.m_stageUIs[i].InitializePickItems();
        }

    }

    private InitializeScore(): void 
    {
        this.m_totalScore = 0;
        log(`[BonusGameController] 初始化分數`);

        for (let i = 0; i < this.m_stageUIs.length; i++)
        {
            const stageUI = this.m_stageUIs[i];
            const stageData = this.m_bonusGameState?.stages?.[(i + 1).toString()];

            stageUI.UpdateScore(0);
            stageUI.UpdateTargetScore(stageData?.bounty || 0);
        }
    }



    /**
     * 創建關卡目標數據陣列
     */
    private CreateTargetDataArray(count: number): TargetData[] 
    {
        const datas: TargetData[] = [];


        for (let i = 0; i < count; i++) {
            datas.push({
                index: i,
                state: TargetState.IDLE,
                reward: null
            });
        }

        return datas;
    }

    // ========== 遊戲流程控制 ==========

    /**
     * 設置當前關卡所有 PickItem 的可點擊狀態
     */
    private SetAllPickItemsClickable(clickable: boolean): void 
    {
        log(`[BonusGameController] 設置當前關卡所有 PickItem 的可點擊狀態: ${clickable}`);
        const currentItems = this.GetCurrentStagePickItems();
        currentItems.forEach(item => 
        {
            if (item.GetState() === TargetState.IDLE) 
            {
                item.SetClickable(clickable);
            }
        });
    }

    /**
     * 獲取當前關卡的 PickItem 陣列
     */
    private GetCurrentStagePickItems(): PickItem[] 
    {
        //log(`[BonusGameController] 獲取當前關卡的 PickItem 陣列: ${this.m_currentStage}`);
        return this.m_stageUIs[this.m_currentStage].GetPickItems(); 
    }

    /**
     * 開始遊戲玩法
     */
    public StartGameplay(): void 
    {
        this.m_isGamePlaying = true;

        // 啟用所有 PickItem 的點擊
        this.SetAllPickItemsClickable(true);

        // 開始問號輪播
        this.StartQuestionMarkLoop();

        // 顯示自動遊玩秒數Root
        if(this.m_isReplay)
        {
            this.m_autoPlayTimeRoot.active = false;

        }
        else
        {
            this.m_autoPlayTimeRoot.active = true;
        }
        this.m_autoPlayTimeLabel.string = this.m_autoPlayTime.toString();
        this.ResetIdleTimer();

        // 開始閒置計時器
        this.StartIdleTimer();

        // 播放開始動畫或音效
        log('[BonusGameController] 遊戲開始！');
    }

    /**
     * 顯示當前關卡
     */
    private ShowCurrentStage(): void 
    {
        // 隱藏所有關卡
        for (const stageUI of this.m_stageUIs) 
        {
            stageUI.ShowStage(false);
        }

        //修改所有的問號根節點
        for(let i = 0; i < this.GetCurrentStagePickItems().length; i++)
        {
            this.GetCurrentStagePickItems()[i].SetToQuestionMarkRoot();
        }

        // 更新自動遊玩秒數
        this.m_autoPlayTimeLabel.string = this.m_autoPlayTime.toString();

        this.m_stageUIs[this.m_currentStage].ShowStage(true);

        this.UpdateBulletCountUI(this.m_bulletCount);

        if(this.m_isReplay)
        {
            this.m_seedTargets = this.GetAvailableTargets();
            this.m_seedTargets = tools.GetRandomArrayBySeed(this.m_seedTargets);
            //console.log(`[BonusGameController] seedTargets: ${this.m_seedTargets}`);
        }


    }



    /**
     * 獲取當前關卡的目標數據
     */
    private GetCurrentStageDatas(): TargetData[] 
    {
        switch (this.m_currentStage) 
        {
            case BonusStage.STAGE_1:
                return this.m_stage1Datas;
            case BonusStage.STAGE_2:
                return this.m_stage2Datas;
            case BonusStage.STAGE_3:
                return this.m_stage3Datas;
            default:
                return [];
        }
    }

    // ========== 射擊目標邏輯 ==========

    /**
     * 玩家點擊射擊（隨機選擇一個目標）
     * 這個方法應該由UI按鈕或玩家操作觸發
     */
    public OnPlayerShoot(targetIndex: number): void 
    {
        if (!this.m_isGamePlaying) 
        {
            warn('[BonusGameController] 遊戲尚未開始');
            return;
        }

        // 重置閒置計時器（玩家有互動）
        //this.ResetIdleTimer();


        this.ShootTarget(targetIndex);
    }

    private UpdateTotalScore(): void 
    {
        for (const stageUI of this.m_stageUIs) 
        {
            stageUI.UpdateScore(this.m_totalScore);
        }
    }



    /**
     * 射擊指定的目標
     */
    private async ShootTarget(targetIndex: number): Promise<void> 
    {
        let currentDatas = this.GetCurrentStageDatas();
        let data = currentDatas[targetIndex];

        if (!data || data.state !== TargetState.IDLE) 
        {
            error(`[BonusGameController] 無效的目標或目標已被射擊: ${targetIndex}`);
            return;
        }

        // 暫停閒置計時器（射擊過程中）
        this.StopIdleTimer();

        // 暫停問號輪播
        this.StopQuestionMarkLoop();

        // 禁用所有其他 PickItem
        this.SetAllPickItemsClickable(false);


        // 更新目標狀態
        data.state = TargetState.REVEALING;
        log(`[BonusGameController] 取值: ${this.m_currentStage+1}, ${this.m_shootCount}`);
        data.reward = this.m_bonusGameState.stages[this.m_currentStage+1].rewards[this.m_shootCount];
        log(`[BonusGameController] 射擊目標: ${targetIndex}, 資料: ${data.reward?.type}, ${data.reward?.value}`);
        // 獲取對應的 PickItem 並播放射擊動畫
        let currentItems = this.GetCurrentStagePickItems();
        const pickItem = currentItems[targetIndex];

        //Common.SetLockOrientation(true);
        // 播放牛仔射擊動畫
        await this.CowboyPlayShootAnimations(pickItem?.GetShootDirection(this.m_bonusGameDirection));

        // 禁用其他目標
        for(let i = 0; i < currentItems.length; i++)
        {
            if(i !== targetIndex)
            {
                currentItems[i].SetClickable(false);
            }

        }

        // 射擊目標
        if (pickItem) 
        {
            await pickItem.Shoot(data.reward);
            this.m_totalScore += data.reward.value;
            if(this.m_totalScore >= this.m_maxWin)
            {
                this.m_totalScore = this.m_maxWin;
            }
            this.UpdateTotalScore();
            newBottombarManager.SetWinValue(this.m_preRoundWin + this.m_totalScore);
            this.m_shootCount++;

        }

        // 處理獎勵
        await this.RevealTarget(data);

        //Common.SetLockOrientation(false);


        // 播放牛仔結果動畫
        //let isMiss = data.reward?.type === protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_MISS;
        await this.CowboyPlayResultAnimations(data);

        // 檢查是否需要前往下一關
        log(`[BonusGameController] 當前關卡: ${this.m_currentStage}, 關卡數: ${Object.keys(this.m_bonusGameState.stages).length}`);
        if(this.m_shootCount >= this.m_bonusGameState.stages[this.m_currentStage+1].rewards.length)
        {
            await Define.Wait(this, 0.5);
            if( this.m_currentStage + 1 < Object.keys(this.m_bonusGameState.stages).length)
            {
                await this.GoToNextStage();
            }
            else
            {
                await this.CheckGameContinue();
            }
        }

        if(this.m_isGamePlaying) //有可能已經結束遊戲,所以這邊要判斷
        {
            // 重新獲取當前關卡的 PickItem 和目標數據
            currentItems = this.GetCurrentStagePickItems();
            currentDatas = this.GetCurrentStageDatas();
            for(let i = 0; i < currentItems.length; i++)
            {
                if(currentDatas[i].state === TargetState.IDLE)
                {
                    currentItems[i].SetClickable(true);
                }

            }
            log(`[BonusGameController] 重新啟動問號輪播`);                 
            this.StartQuestionMarkLoop();

            // 重新啟動閒置計時器
            this.StartIdleTimer();
        }
    }

    /**
     * 顯示目標結果並處理獎勵
     */
    private async RevealTarget(data: TargetData): Promise<void> 
    {
        if (!data.reward) 
        {
            error('[BonusGameController] 目標沒有獎勵數據');
            return;
        }
        return new Promise<void>(async (resolve) => 
        {

            data.state = TargetState.REVEALED;

            const rewardType = data.reward.type;
            const rewardValue = data.reward.value || 0;

            switch (rewardType) 
            {
                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_COIN:
                    // 寶箱/愛心/錢袋 - 獲得獎金
                    await this.HandleCoinReward(rewardValue);
                    break;

                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_TARGET_SYMBOL:
                    // 指定圖騰 - 獲得獎金並前往下一關（除非是最後一關）
                    await this.HandleTargetSymbolReward(rewardValue);
                    break;

                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_MISS:
                    // MISS - 失去一次機會
                    await this.HandleMissReward();
                    break;

                case protocol.ar2fwProto.BonusGameRewardType.BONUS_REWARD_NEXT_STAGE:
                    // 下一關卡圖 - 前往下一關
                    await this.HandleNextStageReward();
                    break;

                default:
                    warn(`[BonusGameController] 未知的獎勵類型: ${rewardType}`);
                    break;
            }




            resolve();
        });
    }

    // ========== 獎勵處理 ==========



    /**
     * 處理金幣獎勵（寶箱/愛心/錢袋）
     */
    private async HandleCoinReward(value: number): Promise<void>  
    {
        log(`[BonusGameController] 獲得金幣: ${value}`);
        return new Promise<void>(async (resolve) => 
        {
            resolve();
        });
    }

    /**
     * 處理指定圖騰獎勵
     */
    private HandleTargetSymbolReward(value: number): Promise<void> 
    {
        log(`[BonusGameController] 獲得指定圖騰獎金: ${value}`);
        return new Promise<void>(async (resolve) => 
        {
            resolve();
        });
    }

    /**
     * 處理MISS獎勵
     */
    private HandleMissReward(): Promise<void> 
    {
        log('[BonusGameController] MISS! 失去一次機會');
        return new Promise<void>(async (resolve) => 
        {
            this.m_bulletCount--;
            resolve();
            AudioManager.Play(AudioManager.AudioClips.BG_LoseChance);
            await this.m_stageUIs[this.m_currentStage].PlayBulletCountAnimation(this.m_bulletCount, this.m_bonusGameDirection);
            this.UpdateBulletCountUI(this.m_bulletCount);



        });
    }

    /**
     * 處理下一關卡獎勵
     */
    private HandleNextStageReward(): Promise<void> 
    {
        log('[BonusGameController] 前往下一關！');
        return new Promise<void>(async (resolve) => 
        {
            resolve();
        });
    }

    // ========== 關卡切換 ==========

    /**
     * 前往下一關
     */
    private async GoToNextStage(): Promise<void> 
    {
        if (this.m_currentStage >= BonusStage.STAGE_3) 
        {
            log('[BonusGameController] 已經是最後一關');
            return;
        }
        this.m_gameView.IsLockRotation = true;
        return new Promise<void>(async (resolve) => 
        {

            await Define.Wait(this, 0.1);
            // 停止閒置計時器（關卡切換期間）
            this.StopIdleTimer();
            this.ResetIdleTimer();

            for(let i = 0; i < this.GetCurrentStagePickItems().length; i++)
            {
                this.GetCurrentStagePickItems()[i].ResetQuestmarkRoot();
            }
            this.m_currentStage++;
            this.m_shootCount = 0;
            log(`[BonusGameController] 進入關卡 ${this.m_currentStage}`);

            // 隱藏子彈根節點
            /*if (this.m_bulletRoot) 
            {
                this.m_bulletRoot.active = false;
            }*/
            AudioManager.Play(AudioManager.AudioClips.BG_Run);
            await this.CowboyLeave();




            this.m_gameView.PlayBGBgmFadeOut(1);


            //播放關卡切換動畫
            await this.PlayTransitionEffect(() => this.ShowCurrentStage());



            // 播放Bonus Game音樂
            if(this.m_gameView)
            {
                this.m_gameView.PlayBonusGameBgm(this.m_currentStage);
                this.m_gameView.PlayBGBgmFadeIn(1,1);
            }


            AudioManager.Play(AudioManager.AudioClips.BG_Run);
            await this.CowboyEnter();

            // 顯示子彈根節點
            /*if (this.m_bulletRoot) 
            {
                this.m_bulletRoot.active = true;
            }*/


            // 新關卡開始後重新啟動閒置計時器
            this.StartIdleTimer();
            resolve();
            this.m_gameView.IsLockRotation = false;
        });
    }

    // ========== 遊戲結束 ==========

    /**
     * 檢查遊戲是否可以繼續
     */
    private CheckGameContinue(): Promise<void> 
    {
        return new Promise<void>(async (resolve) => 
        {
            if(this.m_bonusGameState.stages[this.m_currentStage+1].rewards.length == this.m_shootCount)
            {
                await this.EndGame();
            }
            resolve();
        });
    }

    /**
     * 結束遊戲
     */
    private async EndGame(): Promise<void> 
    {
        log(`[BonusGameController] 遊戲結束！總獎金: ${this.m_totalScore}`);


        return new Promise<void>(async (resolve) => 
        {
            if (this.m_bulletRoot) 
            {
                this.m_bulletRoot.active = false;
            }
            this.m_isGamePlaying = false;

            // 停止閒置計時器
            this.StopIdleTimer();

            // 停止問號輪播
            this.StopQuestionMarkLoop();


            AudioManager.Play(AudioManager.AudioClips.BG_End_MaskFocusCowboy);
            this.m_transitionFocusMask.Show(2000, 300, 0.4);   // 畫面聚焦到牛仔身上
            await Define.Wait(this, 0.2);
            //await 等牛仔的ending pose
            this.CowboySmile();
            await Define.Wait(this, 2);
            AudioManager.Play(AudioManager.AudioClips.BG_End_MaskClose);
            await this.m_transitionFocusMask.Show(300, 0, 0.2);  // 聚焦到畫面全黑


            //AudioManager.Play(AudioManager.AudioClips.BG_Run);
            this.CowboyLeave();
            if (this.m_cowboyRoot) 
            {
                this.m_cowboyRoot.active = false;
            }


            //await Define.Wait(this, 1.0);
            await this.FadeOutTransition(async () => 
                {
                    if (this.m_gameCompleteCallback) {
                        this.m_gameCompleteCallback();
                    }

                    // 發送遊戲結束事件
                    eventManager.Dispatch(BONUS_GAME_EVENT.END, this.m_totalScore);

                    // 隱藏Bonus Game UI
                    this.Hide();
                    //復原所有的問號根節點
                    for(let i = 0; i < this.m_stageUIs.length; i++)
                    {
                        for(let j = 0; j < this.m_stageUIs[i].GetPickItems().length; j++)
                        {
                            this.m_stageUIs[i].GetPickItems()[j].ResetQuestmarkRoot();
                        }

                    }
                    // 停止特殊遊戲BGM
                    if(this.m_gameView)
                    {
                        this.m_gameView.PlayBGBgmFadeOut(1);
                        //this.m_gameView.StopBonusGameBgm();
                    }

                    // 隱藏自動遊玩秒數Root
                    this.m_autoPlayTimeRoot.active = false;
                    this.m_transitionFocusMask.Hide();   // 關閉轉場mask
                    resolve();

                });


        });
    }

    /**
     * 隱藏 Bonus Game
     */
    private Hide(): void 
    {
        if (this.m_displayRoot) 
        {
            this.m_displayRoot.active = false;
        }

        for (const stageUI of this.m_stageUIs) 
        {
            stageUI.ShowStage(false);
        }

    }

    // ========== UI 更新 ==========

    /**
     * 更新子彈數量UI
     */
    private  UpdateBulletCountUI(bulletCount: number): void
    {

        // 更新子彈數量顯示
        log(`[BonusGameController] 剩餘機會: ${bulletCount}`);
        this.m_stageUIs[this.m_currentStage].UpdateBulletCount(bulletCount, this.m_bonusGameDirection);

    }





    // ========== 動畫播放 ==========

    /**
     * 播放射擊動畫
     */
    private PlayShootAnimation(targetIndex: number, callback: () => void): void 
    {
        // TODO: 播放射擊特效和音效
        log(`[BonusGameController] 射擊目標 ${targetIndex}`);

        // 模擬動畫時間
        this.scheduleOnce(() => {
            if (callback) {
                callback();
            }
        }, 0.5);
    }




    // ========== 轉場特效 ==========

    /**
     * 初始化轉場遮罩
     */
    private InitializeTransitionMask(): void 
    {
        if (!this.m_transitionMask) {
            warn('[BonusGameController] 轉場遮罩節點未設定');
            return;
        }

        // 獲取或添加 UIOpacity 組件
        this.m_transitionMaskOpacity = this.m_transitionMask.getComponent(UIOpacity);
        if (!this.m_transitionMaskOpacity) {
            this.m_transitionMaskOpacity = this.m_transitionMask.addComponent(UIOpacity);
        }

        // 初始設為完全透明
        this.m_transitionMaskOpacity.opacity = 0;

        // 確保遮罩在最上層但初始不顯示
        this.m_transitionMask.active = false;

        // 確保有 Sprite 組件用於顯示黑色
        let sprite = this.m_transitionMask.getComponent(Sprite);
        if (sprite) {
            sprite.color = new Color(0, 0, 0, 255); // 黑色
        }
    }

    /**
     * 播放轉場特效
     * @param callback 轉場完成後的回調（在黑章最濃時執行）
     * @returns Promise，在整個轉場動畫完成後 resolve
     */
    private PlayTransitionEffect(callback?: () => void): Promise<void> 
    {
        return new Promise<void>((resolve) => {
            if (!this.m_transitionMask || !this.m_transitionMaskOpacity) {
                warn('[BonusGameController] 轉場遮罩未初始化');
                if (callback) callback();
                resolve();
                return;
            }

            if (this.m_isTransitioning) {
                warn('[BonusGameController] 轉場特效正在進行中');
                resolve();
                return;
            }

            this.m_isTransitioning = true;
            this.m_transitionMask.active = true;

            log('[BonusGameController] 播放轉場特效');
            // 淡入（變黑）-> 停留 -> 執行回調 -> 淡出（變透明）
            tween(this.m_transitionMaskOpacity)
                // 淡入：0 -> 255
                .to(this.m_transitionFadeInDuration, { opacity: 255 })
                // 停留
                .delay(this.m_transitionHoldDuration)
                // 在黑章最濃時執行回調（切換場景）
                .call(() => {
                    if (callback) {
                        callback();
                    }
                })
                // 淡出：255 -> 0
                .to(this.m_transitionFadeOutDuration, { opacity: 0 })
                // 完成
                .call(() => {
                    this.m_transitionMask.active = false;
                    this.m_isTransitioning = false;
                    log('[BonusGameController] 轉場特效完成');
                    resolve();
                })
                .start();
        });
    }

    /**
     * 快速淡入黑章（用於遊戲開始）
     */
    private async FadeInTransition(): Promise<void> 
    {
        return new Promise<void>((resolve) => {
            if (!this.m_transitionMask || !this.m_transitionMaskOpacity) {
                warn('[BonusGameController] 轉場遮罩未初始化');
                resolve();
                return;
            }

            this.m_transitionMask.active = true;
            this.m_transitionMaskOpacity.opacity = 255; // 完全黑

            tween(this.m_transitionMaskOpacity)
                .to(this.m_transitionFadeOutDuration, { opacity: 0 })
                .call(() => {
                    this.m_transitionMask.active = false;

                    resolve();
                })
                .start();
        });
    }

    /**
     * 快速淡出到黑章並結束遊戲（用於遊戲結束）
     */
    private async FadeOutTransition(callback?: () => Promise<void>): Promise<void> 
    {

        return new Promise<void>((resolve) => {
            if (!this.m_transitionMask || !this.m_transitionMaskOpacity) {
                warn('[BonusGameController] 轉場遮罩未初始化');
                resolve();
                return;
            }

            this.m_transitionMask.active = true;

            tween(this.m_transitionMaskOpacity)
                .to(this.m_transitionFadeInDuration, { opacity: 255 })
                .call(async () => {
                    if (callback) {
                        await callback();
                    }

                    tween(this.m_transitionMaskOpacity)
                        .to(this.m_transitionFadeOutDuration, { opacity: 0 })
                        .call(() => {
                            this.m_transitionMask.active = false;

                            resolve();
                        })
                        .start();
                }).start();

        });
    }


    private CheckIdleAutoPlay(): void
    {
        this.m_idleElapsedTime += 0.1;


        let remainTime = this.m_autoPlayTime - this.m_idleElapsedTime;
        if(this.m_isReplay)
        {
            remainTime = 5 - this.m_idleElapsedTime;   
        }

        //log(`[BonusGameController] 剩餘時間: ${remainTime}`);
        if(remainTime > 0)
        {
            this.m_autoPlayTimeLabel.string = Math.ceil(remainTime).toString();
        }
        else
        {
            this.m_autoPlayTimeLabel.string = "0";
        }

        // 當閒置時間達到設定值時，觸發自動遊玩
        if (this.m_idleElapsedTime >= this.m_autoPlayTime)
        {
            log(`[BonusGameController] 閒置 ${this.m_autoPlayTime} 秒，觸發自動遊玩`);
            this.OnIdleAutoPlay();
        }
    }

    /**
     * 開始閒置計時器
     */
    private StartIdleTimer(): void
    {
        // 先停止現有的計時器
        this.StopIdleTimer();

        if (!this.m_isGamePlaying)
        {
            return;
        }

        log('[BonusGameController] 開始閒置計時器');
        //this.m_idleElapsedTime = 0;

        // 每0.1秒檢查一次
        this.schedule(this.CheckIdleAutoPlay, 0.1);
    }

    /**
     * 停止閒置計時器
     */
    private StopIdleTimer(): void
    {

        log('[BonusGameController] 停止閒置計時器');
        this.unschedule(this.CheckIdleAutoPlay);
        //this.m_idleElapsedTime = 0;

    }

    /**
     * 重置閒置計時器（玩家有互動時調用）
     */
    private ResetIdleTimer(): void
    {
        log('[BonusGameController] 重置閒置計時器');
        this.m_idleElapsedTime = 0;
    }

    /**
     * 閒置自動遊玩
     */
    private OnIdleAutoPlay(): void
    {
        if (!this.m_isGamePlaying)
        {
            warn('[BonusGameController] 遊戲未進行中，取消自動遊玩');
            return;
        }

        // 獲取可射擊的目標
        let availableTargets = this.GetAvailableTargets();
        if(this.m_isReplay)
        {
            availableTargets = this.GetReplayTargets();
            //console.log(`[BonusGameController] 重播 ${availableTargets}`);
        }

        if (availableTargets.length === 0)
        {
            warn('[BonusGameController] 沒有可射擊的目標');
            this.StopIdleTimer();
            return;
        }

        // 隨機選擇一個目標
        const randomIndex = Math.floor(Math.random() * availableTargets.length);
        let targetIndex = availableTargets[randomIndex];
        if(this.m_isReplay)
        {
            targetIndex = availableTargets[0];
            //console.log(`[BonusGameController] 重播選擇目標:--------- ${targetIndex}`);
        }

        log(`[BonusGameController] 自動選擇目標: ${targetIndex}`);

        // 執行射擊
        let currentItems = this.GetCurrentStagePickItems();
        const pickItem = currentItems[targetIndex];
        pickItem.PreHandlePlayerShoot();
        this.OnPlayerShoot(targetIndex);
    }

    /**
     * 獲取當前可射擊的目標索引列表
     */
    private GetAvailableTargets(): number[]
    {
        const currentDatas = this.GetCurrentStageDatas();
        const availableTargets: number[] = [];
        for (let i = 0; i < currentDatas.length; i++)
        {
            if (currentDatas[i].state === TargetState.IDLE)
            {
                availableTargets.push(i);
            }
        }


        return availableTargets;
    }

    //重播時獲取可射擊的目標索引列表
    private GetReplayTargets(): number[]
    {
        const currentDatas = this.GetCurrentStageDatas();
        const availableTargets: number[] = [];

        for (let i = 0; i < currentDatas.length; i++)
        {
            if (currentDatas[this.m_seedTargets[i]].state === TargetState.IDLE)
            {
                availableTargets.push(this.m_seedTargets[i]);
            }
        }
        return availableTargets;
    }
}

