import { _decorator, Component, TextAsset } from 'cc';
import Game_Define, { RespinType } from './Game_Define';
import { eventManager } from 'db://astarte-framework/Managers';
import { Common } from './Common/Common';

const { ccclass, property } = _decorator;

/**@ch 假轉輪帶 */
class FakeReel {
    /**@ch 目前假轉輪帶索引，對應m_symbols，每取得一個符號後索引+1 */
    private m_index: number = 0;
    /**@ch 假轉輪帶符號，以m_symbolsPrototype為基礎，符號為負數表示神秘符號，會用m_mysterySymbols替換 */
    private m_symbols: number[] = [];
    /**@ch 假轉輪帶原始符號，符號為負數表示神秘符號，會用m_mysterySymbols替換，其他為假轉輪帶原始符號 */
    private m_symbolsPrototype: number[] = [];
    /**@ch 神秘符號 */
    private m_mysterySymbols: number[] = [];

    /**@ch 添加假轉輪帶資料 */
    AddFakeData(data: number) {
        this.m_symbolsPrototype.push(data);
    }

    /**@ch 重置假轉輪帶 */
    Reset(symbolIdx: number, mysterySymbols: number[]) {
        if (symbolIdx < 0) {
            //@ch 隨機選擇一個位置開始
            this.m_index = Math.floor(Math.random() * this.m_symbolsPrototype.length);
        }
        else {
            //@ch 指定位置開始
            this.m_index = symbolIdx;
        }

        //@ch 設定神秘符號
        this.m_mysterySymbols.length = mysterySymbols.length;
        for (let i = 0; i < mysterySymbols.length; i++) {
            this.m_mysterySymbols[i] = mysterySymbols[i];
        }

        //@ch 設定假轉輪帶符號
        this.m_symbols.length = this.m_symbolsPrototype.length;
        for (let i = 0; i < this.m_symbolsPrototype.length; i++) {
            let symbol = this.m_symbolsPrototype[i];
            if (symbol < 0) {
                // 如果是負數，則轉換為正數，然後使用對應的神秘符號
                symbol = -symbol - 1;
                if (symbol < this.m_mysterySymbols.length) {
                    symbol = this.m_mysterySymbols[symbol];
                }
                else {
                    symbol = 0;
                }
            }
            this.m_symbols[i] = symbol;
        }
    }

    /**@ch 獲取下一個假轉輪帶符號 */
    GetNextFakeSymbol(): number {
        const symbol = this.m_symbols[this.m_index];
        ++this.m_index;
        if (this.m_index >= this.m_symbols.length) {
            this.m_index = 0;
        }
        return symbol;
    }
}

/**@ch 假轉輪盤面 */
class FakePlate {
    /**@ch 假轉輪帶 */
    private m_fakeReels: FakeReel[] = [];

    constructor(textAsset: TextAsset) {
        for (let i = 0; i < Game_Define.COL; i++) {
            this.m_fakeReels.push(new FakeReel());
        }

        try {
            this.ParseData(textAsset.text);
        } catch (err) {
            console.error(`[FakePlate] 解析假轉輪帶檔案失敗: ${err}`);
        }
    }

    /** 解析假轉輪帶檔案內容 */
    private ParseData(fileContent: string): void {
        const data = Common.ParseReelData(fileContent);

        for (let i = 0; i < data.length; i++) {
            const symbolData = data[i];

            // 確保每行都有 Game_Define.COL 個轉輪帶資料
            if (symbolData.length === Game_Define.COL) {
                this.AddFakeRowData(symbolData);
            }
        }
    }

