/**@ch 根據respin類型獲取symbols並設置到node上 */
private GetRespinSymbolsAndSet(targetCol: number, node: ColumnSymbol) {
    let symbols;
    if (this.m_respinType !== RespinType.None && this.m_respinCols && this.m_respinCols.length > 0) {
        if (this.m_respinCols[0] === targetCol) {
            // respin的第一輪

            symbols = this.CheckIsRespinAndGetSymbols(targetCol, Game_Define.ROW);

            this.m_respinCols.forEach(col => {
                if (col === targetCol || this.m_colDelayTime[col] !== 0) {
                    return;
                }

                // 同步其他輪的symbol
                this.m_allColumns[node.PlateIndex][col].SetSymbols(symbols, false);
            });
        }
        else {
            if (this.m_colDelayTime[targetCol] !== 0) {
                // 在有delayTime時(剛開始轉動時)，主動去同步respin第一輪的symbol
                symbols = this.m_allColumns[node.PlateIndex][this.m_respinCols[0]].Symbols;
            }
            else {
                // 如果delayTime已減到0，交給respin的第一輪來同步
                return;
            }
        }
    }
    else {
        symbols = this.CheckIsRespinAndGetSymbols(targetCol, Game_Define.ROW);
    }
    node.SetSymbols(symbols);
}

/**@ch 幫單個column換Symbol */
ChangeSymbol(col: number, node: ColumnSymbol, isStop: boolean) {
    let index = Number(node.Name);
    let reelPreTime = this.m_reelPreTime[col];
    let riseTime = this.m_riseTime * this.m_viewSize.height * SHOW_COLUMNS;

    if (isStop) {
        // 中間輪帶
        if (!isNaN(index)) {
            node.SetSymbols(this.m_plateInfo.PlateSymbol[index].Col);
        }
        else {
            this.GetRespinSymbolsAndSet(col, node);
        }
    }
    else {
        if (!isNaN(index) && ((reelPreTime !== null && this.m_time >= reelPreTime))
        ) {
            node.SetSymbols(this.m_plateInfo.PlateSymbol[index].Col);
        }
        else {
            this.GetRespinSymbolsAndSet(col, node);
        }
    }
}

/**@ch 根據respin type來判斷要怎麼隨機產生symbol */
CheckIsRespinAndGetSymbols(col: number, symbolNumber: number) {
    let symbols = [];
    for (let i = 0; i < symbolNumber; ++i) {
        symbols.push(this.RandomSymbol(col));
    }
    return symbols.reverse(); // 因為餵給ColumnSymbol的symbols會反過來顯示，所以這邊要反回來
}

/**@ch 最後一道防線 */
CheckChangeToFinalSymbol(col: number, node: ColumnSymbol, isStop = false) {
    let index = node.Name;
    if (!this.m_isChangeToFinalSymbol[index]) {
        this.m_isChangeToFinalSymbol[index] = true;
        this.ChangeSymbol(col, node, isStop);
    }
}

/**@ 確認播放停輪音效 */
CheckPlayStopSound(col: number) {
    if (this.m_isPlayStopSound[col]) {
        return;
    }


    let isQuickStop = this.m_isClickStopBtn;
    if (isQuickStop && col !== Game_Define.COL - 1 && this.m_reelStopTime[col] !== this.m_reelStopTime[col + 1]) {
        // 快速停輪時，如果當前列的stopTime和後面列的stopTime不一樣，代表該輪沒有和後面列同步停輪，所以先單獨播當前列的停輪音效
        isQuickStop = false;
    }

    if (isQuickStop) {
        // 播放快速停輪音效
        this.PlayReelStopSound_QuickStop(col);
    }
    else {
        // 播放單一列停輪音效
        this.PlayReelStopSound(col);
        this.m_isPlayStopSound[col] = true;
    }
}

/**@ch 設置當局盤面資料，並設置停輪時間 */
SetPlateInfo(content: protocol.ar2fwProto.IPlateInfo) {
    this.m_plateInfo = content;

    // 設置Scatter symbol位置
    this.m_scatterSymbolPos.clear();
    if (this.m_plateInfo.FeaturePosQueue.length > 0) {
        const featurePosData = this.m_plateInfo.FeaturePosQueue[0].Data;
        if (featurePosData) {
            for (let i = 0; i < featurePosData.length; i++) {
                const { col, row } = Game_Define.SymbolPositions[featurePosData[i]];
                this.m_scatterSymbolPos.set(col, row);
            }

            if (this.m_scatterSymbolPos.size > 0) {

                // 計算這手會出現scatter聽牌框表演的總數量
                const nearWinCols = Array.from(this.m_scatterSymbolPos.keys()).sort((a, b) => a - b);
                if (this.m_scatterSymbolPos.size >= SCATTER_COUNT_FOR_NEAR_WIN_FRAME) {
                    this.m_scatterNearWinFrameTotalCount = Game_Define.COL - nearWinCols[SCATTER_COUNT_FOR_NEAR_WIN_FRAME - 1] - 1;
                }

                // 設定是否播放Scatter定位音
                if (this.m_scatterNearWinFrameTotalCount > 0) {
                    // 有表演Scatter聽牌框，則全部都要播
                    nearWinCols.forEach(col => {
                        this.m_isPlayScatterStopSound[col] = true;
                    });
                }
                else if (nearWinCols[0] < Game_Define.COL - SCATTER_COUNT_FOR_NEAR_WIN_FRAME) {
                    // 第一個Scatter在第三列之前才要播(第四列才有scatter絕對不會進BonusGame，所以不播)
                    if (nearWinCols.length === 2 && nearWinCols[1] === Game_Define.COL - 1) {
                        // 雖然第一個Scatter在第三列之前，但Scatter只有兩個，而且第二個在最後一列，一樣不會進BonusGame，所以只播第一個
                        this.m_isPlayScatterStopSound[nearWinCols[0]] = true;
                    }
                    else {
                        // 第一個Scatter在第三列之前的其他情況都要播
                        nearWinCols.forEach(col => {
                            this.m_isPlayScatterStopSound[col] = true;
                        });
                    }
                }
            }
        }
    }

    // 設定小偷的Symbol位置
    this.m_thiefSymbolPos.clear();
    if (this.m_plateInfo.RespinTriggerMode === protocol.ar2fwProto.AwardModeFlag.AWARD_MODE_LINE) {
        for (let col = 0; col < this.m_plateInfo.PlateSymbol.length; col++) {
            const column = this.m_plateInfo.PlateSymbol[col].Col;
            for (let row = 0; row < column.length; row++) {
                if (column[row].Symbol === Game_Define.Symbol.Thief) {
                    this.m_thiefSymbolPos.set(col, row);
                }
            }
        }
    }

    if (!this.m_gameView.IsMgOmen) {
        this.SetReelTimes();
    }
}

/**@ch 設置停輪時間相關設定 */
SetReelTimes() {
    if (this.m_gameView.IsMgOmen) {
        return;
    }

    let { timesOfSpin, riseTime } = this.CalculateTimesOfSpin();

    let lockCount = 0;
    if (this.m_isClickStopBtn) {
        // 規格有Rise的話，快停仍有Rise(可參考上海甜心)
        this.QuickStop(timesOfSpin, riseTime);
    }
    else {

        for (let i = 0; i < Game_Define.COL; ++i) {
            if (this.m_lockColumn[i]) {
                ++lockCount;
                this.m_reelStopTime[i] = 0;
                this.m_reelPreTime[i] = 0;
            }

            // 計算總轉圈數
            let totalTimesOfSpin = timesOfSpin + this.m_timesOfBaseSpin;    // 基本轉圈數
            totalTimesOfSpin += (this.m_spinIntervalTimes * (i - lockCount));    // 中間每輪加幾圈
            if (this.m_scatterNearWinFrameTotalCount > 0 && i >= Game_Define.COL - this.m_scatterNearWinFrameTotalCount) {
                totalTimesOfSpin += ((i - (Game_Define.COL - this.m_scatterNearWinFrameTotalCount) + 1) * SCATTER_NEAR_WIN_FRAME_SPIN_ROUNDS);    // 表演Scatter聽牌框
            }
            this.m_reelStopTime[i] = tools.strip(this.m_spinTime * totalTimesOfSpin);    // 轉圈數 * 每圈時間
            this.m_reelPreTime[i] = tools.strip(this.m_reelStopTime[i] - this.m_spinTime * 0.5);
        }

        // 計算總轉圈數
        let totalTimesOfSpin = timesOfSpin + this.m_timesOfBaseSpin;    // 基本轉圈數
        totalTimesOfSpin += (this.m_spinIntervalTimes * (Game_Define.COL - 1));    // 中間每輪加幾圈
        if (this.m_scatterNearWinFrameTotalCount > 0) {    // 表演Scatter聽牌框
            totalTimesOfSpin += this.m_scatterNearWinFrameTotalCount * SCATTER_NEAR_WIN_FRAME_SPIN_ROUNDS;
        }
        this.m_stopTime = tools.strip(
            this.m_spinTime * totalTimesOfSpin    // 轉圈數 * 每圈時間
            + this.m_spinDelayTime + riseTime + this.m_spinBufferTime01 + this.m_spinBufferTime02    // 其他時間
        );
    }
}

AddReelTimes(addTimes: number) {
    this.m_stopTime = this.m_stopTime + addTimes * this.m_spinTime;

    for (let i = 0; i < Game_Define.COL; ++i) {
        this.m_reelStopTime[i] = this.m_reelStopTime[i] + addTimes * this.m_spinTime;
        this.m_reelPreTime[i] = this.m_reelPreTime[i] + addTimes * this.m_spinTime * 0.5;
    }
}

/**@ch 壓黑盤面 */
SetSymbolDark(isDark: boolean, col: number) {
    for (let column = 0; column < Game_Define.COL; ++column) {
        if (column === col) {
            for (let i = 0; i < SHOW_COLUMNS; ++i) {
                this.m_allColumns[i][column].SetSymbolDark(false);
            }
            continue;
        }
        for (let i = 0; i < SHOW_COLUMNS; ++i) {
            this.m_allColumns[i][column].SetSymbolDark(isDark);
        }
    }
}

/**@ch 確認FG 是否只出徽章 TODO 應改為有出金幣 */
CheckFGPlateEqual(content: protocol.ar2fwProto.CColumn[]) {
    for (let col = 0; col < content.length; ++col) {
        if (
            content[col]
            && content[col][0]
            && content[col][0] !== 0
        ) {
            return false;
        }
    }
    return true;
}

/**@ch 檢查此Column已經是否停輪 */
CheckColIsStop(col: number) {
    return this.m_time >= this.m_reelStopTime[col];
}

/**@ch 計算該位移到哪 */
CalculateSpinPos(
    //  totalLength: number, totalTime: number, curTime: number, oneLapTime: number
) {

}

/** @ch 隱藏靜態全盤面 */
async HidePlate(delayTime = 0) {
    await Define.Wait(this, delayTime);
    for (let col = 0; col < Game_Define.COL; ++col) {
        this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].SetColumnVisiable(false);
    }
}

/** @ch 顯示靜態全盤面 */
ShowPlate() {
    // this.m_gameView.EffectPlate.ReturnAll();
    for (let col = 0; col < Game_Define.COL; ++col) {
        this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].SetColumnVisiable(true);
    }
}

/**@ch 取得盤面上的symbol ID*/
GetSymbol(col: number, row: number): number {
    return this.m_plateInfo.PlateSymbol[col].Col[row].Symbol;
}

