    /**@ch 取得盤面上的symbol ID*/
    GetSymbol(col: number, row: number): number {
        return this.m_plateInfo.PlateSymbol[col].Col[row].Symbol;
    }

    /**@ch 設定特定位置的Symbol是否顯示
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ Game_Define.ROW-1)
     * @param isShow 是否顯示
     */
    SetSymbolShow(col: number, row: number, isShow: boolean) {
        this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].SetSymbolShow(row, isShow);
    }

    /**@ch 取得特定位置的Symbol初始世界座標
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @param row 行索引 (0 ~ Game_Define.ROW-1)
     * @returns 世界座標
     */
    GetSymbolWorldPosition(col: number, row: number): Vec3 {
        return this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].GetSymbolWorldPosition(row);
    }

    /**@ch 取得特定column的local座標
     * @param col 列索引 (0 ~ Game_Define.COL-1)
     * @returns local座標
     */
    GetReelLocalPosition(col: number): Vec3 {
        return this.m_reelLocalPos[col];
    }

    /**@ch 計算該轉幾圈 */
    private CalculateTimesOfSpin(): { timesOfSpin: number, riseTime: number } {
        let riseTime = this.m_riseTime * Game_Define.COL;
        let timesOfSpin = Math.ceil((this.m_time - riseTime) / this.m_spinTime);
        timesOfSpin = timesOfSpin !== 0 ? timesOfSpin : 1; // || 1
        return { timesOfSpin, riseTime };
    }

    /**@ch 快速停輪 */
    private QuickStop(timesOfSpin: number, riseTime: number) {
        this.m_stopTime = tools.strip(this.m_spinTime * timesOfSpin + this.m_spinDelayTime + riseTime);
        let reelStopTime = tools.strip(this.m_spinTime * timesOfSpin);
        let reelPreTime = tools.strip(this.m_spinTime * (timesOfSpin - 0.5));
        for (let i = 0; i < Game_Define.COL; ++i) {
            if (this.m_lockColumn[i]) {
                // 鎖定的轉輪立即停止
                this.m_reelStopTime[i] = 0;
                this.m_reelPreTime[i] = 0;
            }
            else {
                this.m_reelStopTime[i] = reelStopTime;
                this.m_reelPreTime[i] = reelPreTime;
            }
        }
        this.m_gameView.EffectPlate.ReturnNearWinFrame_Scatter_All();
    }

    /**@ch 設定特定column的delay時間 */
    public SetColDelayTimeByCurTime(col: number) {
        let delayTime = this.m_time;
        while (delayTime >= this.m_spinTime) {
            delayTime -= this.m_spinTime;
        }
        this.m_colDelayTime[col] = delayTime;
    }

    /**@ch 小偷respin重置假轉輪 */
    private FakeReelReset_ThiefRespin() {
        // 從m_randomSymbols_ThiefRespin中隨機選擇4個不重複symbol    // 小偷respin改用讀取假轉輪帶權重表
        // const mysterySymbols = this.m_randomSymbols_ThiefRespin.sort(() => Math.random() - 0.5).slice(0, 4);

        // 重置假轉輪
        eventManager.Dispatch(Game_Define.GameEvent.FakeReelReset, this.m_respinType, this.m_plateInfo.RespinCols, 0/*, mysterySymbols*/);
    }

    /**@ch Super5 respin重置假轉輪 */
    private FakeReelReset_Super5Respin() {
        // 取得聽牌的symbol 1.先取出已連線的symbol
        const waitingLineId = this.m_plateInfo.WaitingLineIds[0];
        const linePositions = Common.GetLinePositions(waitingLineId, Game_Define.COL);
        const lineSymbols = new Set<number>();
        linePositions.forEach(position => {
            const { col, row } = Game_Define.SymbolPositions[position];
            const symbol = this.GetSymbol(col, row);
            lineSymbols.add(symbol);
        });

        // 取得聽牌的symbol 2.用lineSymbols和m_randomSymbols_Super5Respin比較，多出來的就是聽牌的symbol
        const nearWinSymbol = this.m_randomSymbols_Super5Respin.filter(symbol => !lineSymbols.has(symbol))[0];

        // 聽牌的symbol當第一個mysterySymbols
        const mysterySymbols = [nearWinSymbol];

        // 再從m_randomSymbols_Super5Respin中隨機選擇2個不重複symbol且不是聽牌symbol的symbol
        const randomSymbols = this.m_randomSymbols_Super5Respin.filter(symbol => symbol != nearWinSymbol).sort(() => Math.random() - 0.5).slice(0, 2);
        mysterySymbols.push(...randomSymbols);

        // 重置假轉輪
        eventManager.Dispatch(Game_Define.GameEvent.FakeReelReset, this.m_respinType, this.m_plateInfo.RespinCols, -1, mysterySymbols);
    }

    /**@ch 播放小偷respin轉輪音效 */
    private PlayThiefRespinSound() {
        this.StopThiefRespinSound();
        this.m_thiefRespinSoundId = AudioManager.Play(AudioManager.AudioClips.Thief_Respin);
    }

    /**@ch 停止小偷respin轉輪音效 */
    private StopThiefRespinSound() {
        if (this.m_thiefRespinSoundId !== -1) {
            // 停止小偷respin的轉輪音效
            AudioManager.Stop(this.m_thiefRespinSoundId);
            this.m_thiefRespinSoundId = -1;
        }
    }
}

