import { _decorator, Node, Sprite, v3, Vec3, Layers } from "cc";

import Game_Define from "./Game_Define";
import { Define } from "db://astarte-framework/utilis";
import GameView from "./GameView";
import protocol from "@igs-arcade-division-rd2/uk_746_far_west_proto/ar2fwProto.js"


const { ccclass } = _decorator;
@ccclass("ColumnSymbol")
export class ColumnSymbol {
    private m_parentNode: Node = null;
    private m_symbolSprites: Array<Sprite> = new Array<Sprite>();
    private m_gameView: GameView = null;
    private m_symbols: protocol.ar2fwProto.ICSymbol[] = [];
    public get Symbols() {
        return this.m_symbols;
    }

    private m_name: string = "";
    public get Name() {
        return this.m_name;
    }
    public set Name(v: string) {
        this.m_name = v;
    }

    private m_basePos: Vec3 = v3(0, 0, 0);

    private m_plateIndex: number = -1;
    public get PlateIndex() {
        return this.m_plateIndex;
    }

    private m_colIndex: number = -1;
    public get ColIndex() {
        return this.m_colIndex;
    }

    /**@ch 將每個column的每個row都設定可能出現的東西(sprite, prefab) */
    constructor(parent: Node, viewHeight: number, gameView: GameView, name: string, plateIndex: number, colIndex: number) {
        // super();

        this.m_parentNode = parent;
        this.m_gameView = gameView;
        this.m_plateIndex = plateIndex;
        this.m_colIndex = colIndex;

        for (let row = 0; row < Game_Define.ROW; ++row) {
            let node = new Node();
            node.name = name + row.toString();
            node.layer = Layers.Enum.DEFAULT;//Define.Layer2D;

            let sprite: Sprite = node.addComponent(Sprite);
            sprite.type = Sprite.Type.SIMPLE;
            sprite.sizeMode = Sprite.SizeMode.RAW;
            sprite.trim = false;
            this.m_parentNode.addChild(node);

            this.m_symbolSprites[row] = sprite;
        }
    }

    /**@ch 設定要顯示在盤面上的symbol */
    SetSymbols(symbols: protocol.ar2fwProto.ICSymbol[], setPosition = true) {
        this.m_symbols = symbols;
        for (let row = 0; row < this.m_symbolSprites.length; ++row) {
            // 有些遊戲每個Column的symbol數量不一定
            if (row < symbols.length) {
                this.m_symbolSprites[row].node.active = true;
                this.m_symbolSprites[row].spriteFrame = this.m_gameView.GetSymbolSpriteFrame(symbols[row]);
                if (setPosition) {
                    this.m_symbolSprites[row].node.setPosition(this.CalPosY(row));
                }
            }
            else {
                this.m_symbolSprites[row].node.active = false;
            }
        }
    }

    /**@ch 置換Symbol */
    // ChangeSymbol(symbol: number, row: number) {
    //     this.m_symbolSprites[row].spriteFrame = this.m_gameView.GetSymbolSpriteFrame(symbol);
    //     this.m_symbolSprites[row].node.active = true;
    // }

    /**@ch 設定位置 */
    SetPosition(pos: Vec3) {
        this.m_basePos = pos;
        for (let row = 0; row < this.m_symbols.length; ++row) {
            let pos = this.CalPosY(row);

            this.m_symbolSprites[row].node.setPosition(pos);
        }
    }

    /**@ch 計算Y軸座標，要用clone不然會被pos戳到 */
    CalPosY(row: number): Vec3 {
        let pos = this.m_basePos.clone();
        // 因為上下顛倒，這邊用減的
        pos.y += (Game_Define.ROW - 1 - row + 0.5) * Game_Define.SymbolHeight;
        return pos;
    }

    /**@ch 計算靜止時Y軸座標，多用一個靜止的，省得被其他東西戳到 */
    CalStopPosY(row: number): Vec3 {
        let pos = v3(0, 0, 0);
        // 因為上下顛倒，這邊用減的
        pos.y += (Game_Define.ROW - 2.5 - row + 0.5) * Game_Define.SymbolHeight;
        return pos;
    }

    /**@ch 表演時關閉symbol */
    HideSymbolByRow(row: number) {
        this.m_symbolSprites[row].node.active = false;
    }

    /**@ch 顯示此Col */
    SetColumnVisiable(v: boolean) {
        for (let i = 0; i < Game_Define.ROW; ++i) {
            this.m_symbolSprites[i].node.active = v;
        }
    }

    /**@ch 壓黑此Col */
    SetSymbolDark(setToDark: boolean) {
        for (let i = 0; i < Game_Define.ROW; ++i) {
            if (setToDark) {
                this.m_symbolSprites[i].color = Game_Define.Color.Dark;
            }
            else {
                this.m_symbolSprites[i].color = Game_Define.Color.Light;
            }
        }
    }

    /**@ch 設定特定位置的Symbol是否顯示
     * @param row 行索引 (0 ~ Game_Define.ROW-1)
     * @param isShow 是否顯示
     */
    SetSymbolShow(row: number, isShow: boolean) {
        this.m_symbolSprites[row].node.active = isShow;
    }

    /**@ch 取得特定位置的Symbol初始世界座標
     * @param row 行索引 (0 ~ Game_Define.ROW-1)
     * @returns 世界座標
     */
    GetSymbolWorldPosition(row: number): Vec3 {
        return this.m_symbolSprites[row].node.getWorldPosition();
    }
}

