private GetIdx(name: string) {
    // reg 需依需求調整
    let reg = /Symbol_(\d{2})/g;
    let result: number[] = [];
    let res = reg.exec(name);

    // result 大小依遊戲需求改變(MEGA Way會有兩個參數)
    for (let i = 0; i < res.length; ++i) {
        let value = Number(res[i]);
        if (!isNaN(value)) {
            result.push(value);
        }
    }
    return result;
}

