SetPlateSymbol(content: protocol.ar2fwProto.IPlateInfo) {
    if (!content || content.PlateSymbol.length < Game_Define.COL) {
        content = this.m_gameView.OldRealPlate;
    }

    let plateSymbols = content.PlateSymbol;

    for (let col = 0; col < Game_Define.COL; ++col) {
        this.m_reelStopTime[col] = this.m_reelPreTime[col] = null;

        // 斷線重修盤面
        this.m_allColumns[Game_Define.MIDDLE_PLATE_INDEX][col].SetSymbols(plateSymbols[col].Col);
    }

    for (let plate = 0; plate < SHOW_COLUMNS; ++plate) {
        for (let col = 0; col < Game_Define.COL; ++col) {
            this.m_allColumns[plate][col].SetPosition(v3(this.m_reelXPos[col], this.m_reelYPos[plate]));
        }
    }
}

/**@ch 產生隨機symbol */
private RandomSymbol(col: number) {
    let randSymbol: number = 0;
    let callback = (symbol: number) => {
        randSymbol = symbol;
    };
    eventManager.Dispatch(Game_Define.GameEvent.FakeReelGetNextSymbol, this.m_respinType, col, callback);
    return new protocol.ar2fwProto.CSymbol({ Symbol: randSymbol });
}

/**@ch 開始Spin，處理相關設置 */
StartSpin(respinType: RespinType = RespinType.None) {
    this.m_time = 0;
    this.m_stopTime = 0;
    this.m_isStop = false;
    this.m_isClickStopBtn = false;
    this.m_isPlayStopEffect = [false, false, false, false, false];
    this.m_scatterSymbolPos.clear();
    this.m_thiefSymbolPos.clear();
    this.m_scatterNearWinFrameTotalCount = 0;
    this.m_showScatterCount = 0;
    this.m_isPlayScatterStopSound = [false, false, false, false, false];
    this.m_colDelayTime = [-1, -1, -1, -1, -1];
    this.m_isSuperFail = false;

    for (let i = 0; i < Game_Define.COL; ++i) {
        this.m_reelStopTime[i] = this.m_reelPreTime[i] = null;
    }

    // 上中下輪帶 "換symbol了沒" 變數須設為true
    for (const key in this.m_isNotChangeSymbolThisRound) {
        this.m_isNotChangeSymbolThisRound[key] = true;
    }

    this.m_respinType = respinType;
    this.m_spinTime = this.m_spinTime_Default;
    if (this.m_respinType !== RespinType.None) {

        // 先鎖定所有轉輪
        for (let col = 0; col < this.m_isChangeToFinalSymbol.length; ++col) {
            this.m_isChangeToFinalSymbol[col] = this.m_lockColumn[col] = this.m_isPlayStopSound[col] = true;
        }

        // 再解鎖respin的轉輪
        this.m_respinCols = this.m_plateInfo.RespinCols;
        this.m_respinCols.forEach(col => {
            this.m_isChangeToFinalSymbol[col] = this.m_lockColumn[col] = this.m_isPlayStopSound[col] = false;
        });


        if (this.m_respinType === RespinType.Thief) {
            // 小偷respin

            // 設定小偷respin的m_spinTime
            this.m_spinTime = this.m_spinTime_ThiefRespin;

            // 重置假轉輪
            this.FakeReelReset_ThiefRespin();

