    public OnLeave() {
        this.m_gameView.EffectPlate.ResetAll();
        this.m_gameView.SlotReels.ShowPlate();
    }

    /**@ch 開始spin */
    private StartSpin(respinType: RespinType) {
        this.m_gameView.CurPlateIndex = this.m_gameView.CurPlateIndex + 1;
        this.m_gameView.SlotReels.StartSpin(respinType);
        this.m_isSpinning = true;
    }

    /**@ch 叫牛仔出來表演小偷respin */
    private async CallCowboyForThiefRespin(thiefSymbols: { col: number, row: number }[]): Promise<void> {
        this.m_currentRespinCols = [];
        return new Promise<void>((resolve) => {
            let callbackCount = 0;
            const callback = () => {
                const col = this.m_targetRespinCols[this.m_currentRespinCols.length];
                this.m_currentRespinCols.push(col);
                if (this.m_currentRespinCols.length === 1) {
                    this.StartSpin(RespinType.Thief);
                } else {
                    this.m_gameView.SlotReels.SetColDelayTimeByCurTime(col);
                }

                callbackCount++;
                if (this.m_currentRespinCols.length === this.m_targetRespinCols.length || callbackCount >= thiefSymbols.length) {
                    resolve();
                }
            }

            const callbackArray: (() => void)[] = new Array(thiefSymbols.length).fill(callback);
            eventManager.Dispatch(COWBOY_EVENT.ENTER, thiefSymbols, callbackArray);
        });
    }

    /**@ch 處理spin結束後的流程 */
    private async ProcessAfterStop() {
        if (this.m_isSuper5Respin) {
            // super 5

            if (this.m_gameView.SlotReels.IsSuperFail) {
                // super 5失敗時聽牌框要故意多停留一下
                await Define.Wait(this.m_gameView, RESPIN_WAIT_TIME_SUPER5_FAIL);
            }

            // 停止Super5聽牌動畫
            this.m_gameView.EffectPlate.StopNearWinFrame_Super5();
        }

        this.m_gameView.CanPlateStop = true;
        this.m_gameView.CanSpaceStop = true;
        // this.m_gameView.IsSpined = false;
        if (!newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        }

        stateManager.NextState(Game_Define.GameState.EFFECT_START);
    }
}

