private LoadSymbol() {
    let path = this.m_loadPath.trim() + "Img/Symbol";
    Define.GameBundle.loadDir(
        path,
        SpriteFrame,
        (error: Error, assets: SpriteFrame[]) => {
            if (error) {
                this.LoadSymbol();
                return;
            }

            assets.sort((a: SpriteFrame, b: SpriteFrame) => {
                let AIdx: number[] = this.GetIdx(a.name);
                let BIdx: number[] = this.GetIdx(b.name);

                if (AIdx[0] < BIdx[0]) {
                    return -1;
                }
                else if (AIdx[0] > BIdx[0]) {
                    return 1;
                }
                else {
                    return 0;
                }
            });

            this.m_symbolSpriteFrames = assets;

            // 空節點
            this.m_symbolSpriteFrames.push(null);

            // TODO 因為還沒有轉輪，所以先註解
            this.SlotReels.CreateSymbol();
        });
}
//#endregion Symbol相關

//=============================================================
//#region 設定文字
/**@ch 多語系 */
SetTxt() {
    let logoSprite = this.m_titleSpriteAtlas.getSpriteFrame("logo_" + localeStringManager.CurrLang);
    if (!logoSprite) {
        logoSprite = this.m_titleSpriteAtlas.getSpriteFrame("logo_" + Define.Lang.EN);
    }
}
//#endregion 設定文字
//=============================================================

//=============================================================
//#region 一般功能
private ReqMail() {
    if (Define.APP) {
        ConnectionManager.SendMailReq();
    }
}

/**
 * @ch 初始化額外功能
 */
InitExtra() {
    if (!Define.APP) {
        return;
    }

    this.ReqMail();
    newExtraManager.RecommendNewInit();
    backpackManager.NewInit();
    gaiaManager.JpManagerInit();
    gaiaManager.MhbManagerInit();

    // 如果用公版的BuyBonus，則需要設置buyBonusManager.NewInit
    let startCb: () => void = () => {
        // this.m_buyBonus?.Hide();
        newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        eventManager.Dispatch(CommonEventName.SpinReqNotify);
    };
    let endCb: () => void = () => {
        if (newBottombarManager.IsAutoSpin) {
            newBottombarManager.ShowAutoPlayState(false);
        }
    };
    buyBonusManager.NewInit(startCb, endCb);

    debrisManager.NewInit();

    missionManager.NewInit();
    newExtraManager.RankingInit(
        [Define.APP.GetAccount(), Define.APP.GetNickName()],
        Define.APP.GetAToken(),
        tools.ConvertLanguageToFull(localeStringManager.CurrLang),
        null,
        null,
        () => {
            this.ReqMail();
        }
    );
    giftCodeManager.Init();

    eventManager.Register(CommonEventName.OpenExtraBet, this);
    eventManager.Register(CommonEventName.CloseExtraBet, this);
    eventManager.Register(CommonEventName.TriggerFreeSpin, this);
    eventManager.Register(CommonEventName.FreeSpinTotalWinEnd, this);
}
//endregion 一般功能
//=============================================================

//=============================================================
//#region Spin相關
/**@ch 玩家觸發Spin指令 */
StartSpin() {
    this.m_isHardStop = newBottombarManager.IsHardStop;

    this.m_slotReels.StartSpin();

    // TODO 只有一般遊戲狀態下才歸零贏分
    if (!this.IsBonusGame) {
        newBottombarManager.SetWinValue(0);
    }
}

/**@ch 按下停止按鍵 */
private ClickStop() {
    if (tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)
        || !this.CanSpaceStop
        || !this.CanPlateStop
    ) {
        return;
    }

    if (stateManager.Current() === CommonState.SPIN) {
        if (!newBottombarManager.IsAutoSpin) {
            this.SlotReels.ClickStopBtn();
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
        }
        else if (!this.m_isHardStop) {
            this.SlotReels.ClickStopBtn();
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY);
        }

        this.SlotReels.ClickStopBtn();
    }
    else if (stateManager.Current() === Game_Define.GameState.AWARD) {
        //大獎跳過
        if (newBottombarManager.IsAutoSpin) {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP);
        }
        else {
            newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_STOP);
        }
